module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"일곱 촛대 사이의 인자","verses":{"krv":[{"n":1,"t":"예수 그리스도의 계시라 이는 하나님이 그에게 주사 반드시 속히 될 일을 그 종들에게 보이시려고 그 천사를 그 종 요한에게 보내어 지시하신 것이라"},{"n":2,"t":"요한은 하나님의 말씀과 예수 그리스도의 증거 곧 자기의 본 것을 다 증거하였느니라"},{"n":3,"t":"이 예언의 말씀을 읽는 자와 듣는 자들과 그 가운데 기록한 것을 지키는 자들이 복이 있나니 때가 가까움이라"},{"n":4,"t":"요한은 아시아에 있는 일곱 교회에 편지하노니 이제도 계시고 전에도 계시고 장차 오실 이와 그 보좌 앞에 일곱 영과"},{"n":5,"t":"또 충성된 증인으로 죽은 자들 가운데서 먼저 나시고 땅의 임금들의 머리가 되신 예수 그리스도로 말미암아 은혜와 평강이 너희에게 있기를 원하노라 우리를 사랑하사 그의 피로 우리 죄에서 우리를 해방하시고"},{"n":6,"t":"그 아버지 하나님을 위하여 우리를 나라와 제사장으로 삼으신 그에게 영광과 능력이 세세토록 있기를 원하노라 아멘"},{"n":7,"t":"볼지어다 구름을 타고 오시리라 각인의 눈이 그를 보겠고 그를 찌른 자들도 볼 터이요 땅에 있는 모든 족속이 그를 인하여 애곡하리니 그러하리라 아멘"},{"n":8,"t":"주 하나님이 가라사대 나는 알파와 오메가라 이제도 있고 전에도 있었고 장차 올 자요 전능한 자라 하시더라"},{"n":9,"t":"나 요한은 너희 형제요 예수의 환난과 나라와 참음에 동참하는 자라 하나님의 말씀과 예수의 증거를 인하여 밧모라 하는 섬에 있었더니"},{"n":10,"t":"주의 날에 내가 성령에 감동하여 내 뒤에서 나는 나팔 소리 같은 큰 음성을 들으니"},{"n":11,"t":"가로되 너 보는 것을 책에 써서 에베소, 서머나, 버가모, 두아디라, 사데, 빌라멜비아, 라오디게아 일곱 교회에 보내라 하시기로"},{"n":12,"t":"몸을 돌이켜 나더러 말한 음성을 알아 보려고 하여 돌이킬 때에 일곱 금 촛대를 보았는데"},{"n":13,"t":"촛대 사이에 인자 같은 이가 발에 끌리는 옷을 입고 가슴에 금띠를 띠고"},{"n":14,"t":"그 머리와 털의 희기가 흰 양털 같고 눈 같으며 그의 눈은 불꽃 같고"},{"n":15,"t":"그의 발은 풀무에 단련한 빛난 주석 같고 그의 음성은 많은 물소리와 같으며"},{"n":16,"t":"그 오른손에 일곱 별이 있고 그 입에서 좌우에 날선 검이 나오고 그 얼굴은 해가 힘있게 비취는 것 같더라"},{"n":17,"t":"내가 볼 때에 그 발 앞에 엎드러져 죽은 자 같이 되매 그가 오른손을 내게 얹고 가라사대 두려워 말라 나는 처음이요 나중이니"},{"n":18,"t":"곧 산 자라 내가 전에 죽었었노라 볼지어다 이제 세세토록 살아 있어 사망과 음부의 열쇠를 가졌노니"},{"n":19,"t":"그러므로 네 본 것과 이제 있는 일과 장차 될 일을 기록하라"},{"n":20,"t":"네 본 것은 내 오른손에 일곱 별의 비밀과 일곱 금 촛대라 일곱 별은 일곱 교회의 사자요 일곱 촛대는 일곱 교회니라"}],"kids":[{"n":1,"t":"이것은 예수 그리스도의 계시(드러내 보여 주심)예요. 하나님께서 반드시 속히 일어날 일들을 그분의 종들에게 보여 주시려고 그분께 주신 것이고, 그분이 그 천사를 그분의 종 요한에게 보내셔서 알려 주신 거예요."},{"n":2,"t":"요한은 하나님의 말씀과 예수 그리스도의 증언, 곧 자기가 본 것을 다 증언했어요."},{"n":3,"t":"이 예언의 말씀을 읽는 사람과 듣는 사람들, 그리고 거기에 기록된 것을 지키는 사람들에게는 복이 있어요. 때가 가까이 왔기 때문이에요."},{"n":4,"t":"요한이 아시아에 있는 일곱 교회에 편지를 써요. 이제도 계시고, 전에도 계셨고, 장차 오실 분과 그분의 보좌 앞에 있는 일곱 영,"},{"n":5,"t":"또 신실한 증인이시고 죽은 사람들 가운데서 처음 나신 분이시고 땅의 왕들의 통치자가 되신 예수 그리스도로부터, 은혜와 평강이 여러분에게 함께하기를 빌어요. 그분은 우리를 사랑하셔서 자기의 피로 우리를 우리 죄에서 해방시켜 주셨고,"},{"n":6,"t":"우리를 그분의 아버지 하나님을 위해 한 나라와 제사장들로 삼으셨어요. 그분께 영광과 권세가 영원무궁히 있기를 빌어요. 아멘."},{"n":7,"t":"보세요, 그분이 구름을 타고 오세요. 모든 사람의 눈이 그분을 볼 거예요. 그분을 찌른 사람들도 볼 거예요. 땅에 있는 모든 민족이 그분 때문에 통곡할 거예요. 정말 그렇게 될 거예요. 아멘."},{"n":8,"t":"주 하나님께서 말씀하셨어요. \\"나는 알파와 오메가(처음과 마지막)다. 이제도 있고, 전에도 있었고, 앞으로 올 자다. 전능한 자다.\\""},{"n":9,"t":"나 요한은 여러분의 형제이고, 예수님 안에서 환난과 나라와 인내에 함께 동참하는 사람이에요. 나는 하나님의 말씀과 예수님에 대한 증언 때문에 \\"밧모\\"라는 섬에 있었어요."},{"n":10,"t":"주님의 날(주일)에 내가 성령에 감동되어 있었는데, 내 뒤에서 나팔 소리 같은 큰 음성을 들었어요."},{"n":11,"t":"그 음성이 말씀하셨어요. \\"네가 보는 것을 책에 써서, 에베소, 서머나, 버가모, 두아디라, 사데, 빌라델비아, 라오디게아 일곱 교회에 보내라.\\""},{"n":12,"t":"내가 몸을 돌려서, 내게 말씀하시는 음성이 누구인지 보려고 했을 때, 일곱 금 촛대를 보았어요."},{"n":13,"t":"그 촛대들 사이에는 \\"인자\\"(사람의 아들) 같은 분이 계셨는데, 발까지 내려오는 긴 옷을 입으시고, 가슴에 금띠를 띠고 계셨어요."},{"n":14,"t":"그분의 머리와 털은 흰 양털 같고 눈처럼 희었고, 눈은 불꽃 같았어요."},{"n":15,"t":"그분의 발은 풀무에 단련된 빛나는 청동 같고, 그분의 음성은 많은 물이 흐르는 소리 같았어요."},{"n":16,"t":"그분은 오른손에 일곱 별을 가지고 계셨고, 그 입에서는 양쪽 모두 날카로운 (양날) 검이 나왔고, 그 얼굴은 해가 힘 있게 비추는 것 같았어요."},{"n":17,"t":"내가 그분을 보았을 때, 그분의 발 앞에 엎드러져 죽은 사람처럼 되었어요. 그러자 그분이 오른손을 내게 얹으시고 말씀하셨어요. \\"두려워하지 마라. 나는 처음이고 마지막이며,"},{"n":18,"t":"살아 있는 자다. 내가 전에 죽었지만, 보아라, 이제는 영원무궁히 살아 있다. 또 사망과 \\"음부\\"(죽은 자들이 가는 곳)의 열쇠를 가지고 있다."},{"n":19,"t":"그러므로 네가 본 것과 지금 있는 일들과 앞으로 일어날 일들을 기록해라."},{"n":20,"t":"내 오른손에 있는 일곱 별의 비밀과 일곱 금 촛대의 비밀은 이거다. 일곱 별은 일곱 교회의 사자(천사/메신저)이고, 일곱 촛대는 일곱 교회다.\\""}]}},{"chapter":2,"title":"에베소·서머나·버가모·두아디라 교회","verses":{"krv":[{"n":1,"t":"에베소 교회의 사자에게 편지하기를 오른손에 일곱 별을 붙잡고 일곱 금 촛대 사이에 다니시는 이가 가라사대"},{"n":2,"t":"내가 네 행위와 수고와 네 인내를 알고 또 악한 자들을 용납지 아니한 것과 자칭 사도라 하되 아닌 자들을 시험하여 그 거짓된 것을 네가 드러낸 것과"},{"n":3,"t":"또 네가 참고 내 이름을 위하여 견디고 게으르지 아니한 것을 아노라"},{"n":4,"t":"그러나 너를 책망할 것이 있나니 너의 처음 사랑을 버렸느니라"},{"n":5,"t":"그러므로 어디서 떨어진 것을 생각하고 회개하여 처음 행위를 가지라 만일 그리하지 아니하고 회개치 아니하면 내가 네게 임하여 네 촛대를 그 자리에서 옮기리라"},{"n":6,"t":"오직 네게 이것이 있으니 네가 니골라 당의 행위를 미워하는도다 나도 이것을 미워하노라"},{"n":7,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 그에게는 내가 하나님의 낙원에 있는 생명나무의 과실을 주어 먹게 하리라"},{"n":8,"t":"서머나 교회의 사자에게 편지하기를 처음이요 나중이요 죽었다가 살아나신 이가 가라사대"},{"n":9,"t":"내가 네 환난과 궁핍을 아노니 실상은 네가 부요한 자니라 자칭 유대인이라 하는 자들의 훼방도 아노니 실상은 유대인이 아니요 사단의 회라"},{"n":10,"t":"네가 장차 받을 고난을 두려워 말라 볼지어다 마귀가 장차 너희 가운데서 몇 사람을 옥에 던져 시험을 받게 하리니 너희가 십 일 동안 환난을 받으리라 네가 죽도록 충성하라 그리하면 내가 생명의 면류관을 네게 주리라"},{"n":11,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 자는 둘째 사망의 해를 받지 아니하리라"},{"n":12,"t":"버가모 교회의 사자에게 편지하기를 죄우에 날선 검을 가진 이가 가라사대"},{"n":13,"t":"네가 어디 사는 것을 내가 아노니 거기는 사단의 위가 있는 데라 네가 내 이름을 굳게 잡아서 내 충성된 증인 안디바가 너희 가운데 곧 사단의 거하는 곳에서 죽임을 당할 때에도 나를 믿는 믿음을 저버리지 아니하였도다"},{"n":14,"t":"그러나 네게 두어 가지 책망할 것이 있나니 거기 네게 발람의 교훈을 지키는 자들이 있도다 발람이 발락을 가르쳐 이스라엘 앞에 올무를 놓아 우상의 제물을 먹게 하였고 또 행음하게 하였느니라"},{"n":15,"t":"이와 같이 네게도 니골라 당의 교훈을 지키는 자들이 있도다"},{"n":16,"t":"그러므로 회개하라 그리하지 아니하면 내가 네게 속히 임하여 내 입의 검으로 그들과 싸우리라"},{"n":17,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다 이기는 그에게는 내가 감추었던 만나를 주고 또 흰 돌을 줄 터인데 그 돌 위에 새 이름을 기록한 것이 있나니 받는 자 밖에는 그 이름을 알 사람이 없느니라"},{"n":18,"t":"두아디라 교회의 사자에게 편지하기를 그 눈이 불꽃 같고 그 발이 빛난 주석과 같은 하나님의 아들이 가라사대"},{"n":19,"t":"내가 네게 사업과 사랑과 믿음과 섬김과 인내를 아노니 네 나중 행위가 처음 것보다 많도다"},{"n":20,"t":"그러나 네게 책망할 일이 있노라 자칭 선지자라 하는 여자 이세벨을 네가 용납함이니 그가 내 종들을 가르쳐 꾀어 행음하게 하고 우상의 제물을 먹게 하는도다"},{"n":21,"t":"또 내가 그에게 회개할 기회를 주었으되 그 음행을 회개하고자 아니하는도다"},{"n":22,"t":"볼지어다 내가 그를 침상에 던질 터이요 또 그로 더불어 간음하는 자들도 만일 그의 행위를 회개치 아니하면 큰 환난 가운데 던지고"},{"n":23,"t":"또 내가 사망으로 그의 자녀를 죽이리니 모든 교회가 나는 사람의 뜻과 마음을 살피는 자인 줄 알지라 내가 너희 각 사람의 행위대로 갚아주리라"},{"n":24,"t":"두아디라에 남아 있어 이 교훈을 받지 아니하고 소위 사단의 깊은 것을 알지 못하는 너희에게 말하노니 다른 짐으로 너희에게 지울 것이 없노라"},{"n":25,"t":"다만 너희에게 있는 것을 내가 올 때까지 굳게 잡으라"},{"n":26,"t":"이기는 자와 끝까지 내 일을 지키는 그에게 만국을 다스리는 권세를 주리니"},{"n":27,"t":"그가 철장을 가지고 저희를 다스려 질그릇 깨뜨리는 것과 같이 하리라 나도 내 아버지께 받은 것이 그러하니라"},{"n":28,"t":"내가 또 그에게 새벽 별을 주리라"},{"n":29,"t":"귀있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다"}],"kids":[{"n":1,"t":"에베소 교회의 사자(천사/메신저)에게 편지를 써라. 오른손에 일곱 별을 붙잡으시고, 일곱 금 촛대 사이에 다니시는 분이 이렇게 말씀하세요."},{"n":2,"t":"\\"나는 네 행위와 수고와 네 인내를 안다. 또 네가 악한 사람들을 용납하지 않은 것과, 자칭 사도라고 말하지만 사도가 아닌 사람들을 시험해서 그 거짓을 드러낸 것을 안다."},{"n":3,"t":"또 네가 인내했고 내 이름을 위해 견뎌 왔으며, 게으르지 않은 것도 안다."},{"n":4,"t":"그러나 너에게 책망할 것이 있다. 네가 처음 사랑을 버렸다."},{"n":5,"t":"그러므로 네가 어디서 떨어졌는지를 생각하고 회개하고, 처음에 했던 행위를 다시 행하라. 만약 그렇게 하지 않고 회개하지 않는다면, 내가 네게 가서 네 촛대를 그 자리에서 옮겨 버리겠다."},{"n":6,"t":"그러나 네게는 이것이 있다. 곧 네가 니골라 당이 한 일들을 미워한다는 거다. 나도 이것을 미워한다."},{"n":7,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라. 이기는 사람에게는 내가 하나님의 낙원에 있는 생명나무의 열매를 주어 먹게 하겠다.\\""},{"n":8,"t":"서머나 교회의 사자에게 편지를 써라. 처음이고 마지막이며, 죽었다가 다시 살아나신 분이 이렇게 말씀하세요."},{"n":9,"t":"\\"나는 네 환난과 가난을 안다. 그러나 사실 너는 부요한 자다. 또 자칭 유대 사람이라 하면서 사실은 유대 사람이 아니라 사탄의 회당인 자들이 너를 비방하는 것도 안다."},{"n":10,"t":"네가 앞으로 받을 고난을 두려워하지 마라. 보아라, 마귀가 앞으로 너희 가운데 몇 사람을 감옥에 던져 시험을 받게 할 것이고, 너희가 열흘 동안 환난을 받을 것이다. 네가 죽기까지 충성하라. 그러면 내가 생명의 면류관을 네게 주겠다."},{"n":11,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라. 이기는 사람은 \\"둘째 사망\\"(영원한 멸망)의 해를 받지 않을 것이다.\\""},{"n":12,"t":"버가모 교회의 사자에게 편지를 써라. 양날의 날카로운 검을 가지신 분이 이렇게 말씀하세요."},{"n":13,"t":"\\"나는 네가 어디에 사는지를 안다. 거기는 사탄의 보좌가 있는 곳이다. 그런데도 너는 내 이름을 굳게 붙잡고 있고, 내 신실한 증인 안디바가 너희 가운데, 곧 사탄이 거하는 곳에서 죽임을 당했을 때에도, 너는 나를 믿는 믿음을 저버리지 않았다."},{"n":14,"t":"그러나 너에게 책망할 것이 두어 가지 있다. 거기에는 발람의 가르침을 지키는 사람들이 있다. 발람은 발락을 가르쳐서, 이스라엘 백성 앞에 올무를 놓아 우상에게 바친 음식을 먹게 하고 음란한 짓을 하게 했다."},{"n":15,"t":"마찬가지로 너에게도 니골라 당의 가르침을 지키는 사람들이 있다."},{"n":16,"t":"그러므로 회개하라. 그렇게 하지 않으면, 내가 네게 속히 가서 내 입의 검으로 그들과 싸우겠다."},{"n":17,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라. 이기는 사람에게는 내가 감추었던 만나를 주고, 또 흰 돌을 주겠다. 그 돌 위에는 새 이름이 기록되어 있는데, 받는 사람 외에는 아무도 그 이름을 알지 못한다.\\""},{"n":18,"t":"두아디라 교회의 사자에게 편지를 써라. 그 눈이 불꽃 같고, 그 발이 빛나는 청동 같은 하나님의 아들이 이렇게 말씀하세요."},{"n":19,"t":"\\"나는 네 행위와 사랑과 믿음과 섬김과 인내를 안다. 네 나중 행위가 처음 행위보다 더 많다."},{"n":20,"t":"그러나 너에게 책망할 일이 있다. 자칭 예언자라고 하는 여자 이세벨을 네가 용납하고 있다는 거다. 그 여자는 내 종들을 가르치고 꾀어 음란한 짓을 하게 하고, 우상에게 바친 음식을 먹게 하고 있다."},{"n":21,"t":"또 내가 그 여자에게 회개할 기회를 주었지만, 그 음행을 회개하려 하지 않는다."},{"n":22,"t":"보아라, 내가 그 여자를 (병의) 침상에 던질 것이고, 그 여자와 함께 간음하는 사람들도 만약 그 여자의 행위를 회개하지 않는다면 큰 환난 가운데 던질 것이다."},{"n":23,"t":"또 내가 그 여자의 자녀들을 죽이겠다. 그러면 모든 교회가 내가 사람의 생각과 마음을 살피는 자라는 것을 알게 될 것이다. 내가 너희 한 사람 한 사람에게 그 행위에 따라 갚아 주겠다."},{"n":24,"t":"그러나 두아디라에 남아 있는 사람들, 곧 이 가르침을 받지 않고 이른바 \\"사탄의 깊은 것\\"을 알지 못하는 너희에게 말한다. 너희에게 다른 짐을 더 지우지 않겠다."},{"n":25,"t":"다만 너희에게 있는 것을 내가 올 때까지 굳게 붙잡고 있어라."},{"n":26,"t":"이기는 사람과 끝까지 내 일을 지키는 사람에게는, 내가 만국을 다스리는 권세를 주겠다."},{"n":27,"t":"\\"그는 철장(쇠 막대기)을 가지고 그들을 다스려, 질그릇을 깨뜨리는 것처럼 부술 것이다.\\" 이는 나도 내 아버지께 받은 권세와 같다."},{"n":28,"t":"내가 또 그에게 새벽 별을 주겠다."},{"n":29,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라.\\""}]}},{"chapter":3,"title":"사데·빌라델비아·라오디게아 교회","verses":{"krv":[{"n":1,"t":"사데 교회의 사자에게 편지하기를 하나님의 일곱 영과 일곱 별을 가진 이가 가라사대 내가 네 행위를 아노니 네가 살았다 하는 이름은 가졌으나 죽은 자로다"},{"n":2,"t":"너는 일깨워 그 남은 바 죽게 된 것을 굳게 하라 내 하나님 앞에 네 행위의 온전한 것을 찾지 못하였노니"},{"n":3,"t":"그러므로 네가 어떻게 받았으며 어떻게 들었는지 생각하고 지키어 회개하라 만일 일깨지 아니하면 내가 도적 같이 이르리니 어느 시에 네게 임할는지 네가 알지 못하리라"},{"n":4,"t":"그러나 사데에 그 옷을 더럽히지 아니한 자 몇 명이 네게 있어 흰 옷을 입고 나와 함께 다니리니 그들은 합당한 자인 연고라"},{"n":5,"t":"이기는 자는 이와 같이 흰 옷을 입을 것이요 내가 그 이름을 생명책에서 반드시 흐리지 아니하고 그 이름을 내 아버지 앞과 그 천사들 앞에서 시인하리라"},{"n":6,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다"},{"n":7,"t":"빌라델비아 교회의 사자에게 편지하기를 거룩하고 진실하사 다윗의 열쇠를 가지신 이 곧 열면 닫을 사람이 없고 닫으면 열 사람이 없는 그이가 가라사대"},{"n":8,"t":"볼지어다 내가 네 앞에 열린 문을 두었으되 능히 닫을 사람이 없으리라 내가 네 행위를 아노니 네가 적은 능력을 가지고도 내 말을 지키며 내 이름을 배반치 아니하였도다"},{"n":9,"t":"보라 사단의 회 곧 자칭 유대인이라 하나 그렇지 않고 거짓말하는 자들 중에서 몇을 네게 주어 저희로 와서 네 발 앞에 절하게 하고 내가 너를 사랑하는 줄을 알게 하리라"},{"n":10,"t":"네가 나의 인내의 말씀을 지켰은즉 내가 또한 너를 지키어 시험의 때를 면하게 하리니 이는 장차 온 세상에 임하여 땅에 거하는 자들을 시험할 때라"},{"n":11,"t":"내가 속히 임하리니 네가 가진 것을 굳게 잡아 아무나 네 면류관을 빼앗지 못하게 하라"},{"n":12,"t":"이기는 자는 내 하나님 성전에 기둥이 되게 하리니 그가 결코 다시 나가지 아니하리라 내가 하나님의 이름과 하나님의 성 곧 하늘에서 내 하나님께로부터 내려오는 새 예루살렘의 이름과 나의 새 이름을 그이 위에 기록하리라"},{"n":13,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다"},{"n":14,"t":"라오디게아 교회의 사자에게 편지하기를 아멘이시요 충성되고 참된 증인이시요 하나님의 창조의 근본이신 이가 가라사대"},{"n":15,"t":"내가 네 행위를 아노니 네가 차지도 아니하고 더웁지도 아니하도다 네가 차든지 더웁든지 하기를 원하노라"},{"n":16,"t":"네가 이같이 미지근하여 더웁지도 아니하고 차지도 아니하니 내 입에서 너를 토하여 내치리라"},{"n":17,"t":"네가 말하기를 나는 부자라 부요하여 부족한 것이 없다 하나 네 곤고한 것과 가련한 것과 가난한 것과 눈 먼 것과 벌거벗은 것을 알지 못하도다"},{"n":18,"t":"내가 너를 권하노니 내게서 불로 연단한 금을 사서 부요하게 하고 흰 옷을 사서 입어 벌거벗은 수치를 보이지 않게 하고 안약을 사서 눈에 발라 보게 하라"},{"n":19,"t":"무릇 내가 사랑하는 자를 책망하여 징계하노니 그러므로 네가 열심을 내라 회개하라"},{"n":20,"t":"볼지어다 내가 문 밖에 서서 두드리노니 누구든지 내 음성을 듣고 문을 열면 내가 그에게로 들어가 그로 더불어 먹고 그는 나로 더불어 먹으리라"},{"n":21,"t":"이기는 그에게는 내가 내 보좌에 함께 앉게 하여 주기를 내가 이기고 아버지 보좌에 함께 앉은 것과 같이 하리라"},{"n":22,"t":"귀 있는 자는 성령이 교회들에게 하시는 말씀을 들을지어다"}],"kids":[{"n":1,"t":"사데 교회의 사자(천사/메신저)에게 편지를 써라. 하나님의 일곱 영과 일곱 별을 가지신 분이 이렇게 말씀하세요. \\"나는 네 행위를 안다. 네가 살았다는 이름은 가지고 있지만, 사실은 죽은 자다."},{"n":2,"t":"너는 깨어나서, 남아 있어 죽어 가는 것을 굳게 하라. 내가 내 하나님 앞에서 네 행위가 온전한 것을 찾지 못했다."},{"n":3,"t":"그러므로 네가 어떻게 받았고, 어떻게 들었는지를 기억하고 그것을 지키며 회개하라. 만약 깨어 있지 않으면, 내가 도둑처럼 갈 것이고, 어느 시간에 네게 갈지 너는 알지 못할 것이다."},{"n":4,"t":"그러나 사데에는 자기 옷을 더럽히지 않은 사람들이 몇 명 있다. 그들은 흰 옷을 입고 나와 함께 다닐 것이다. 그들은 합당한 사람들이기 때문이다."},{"n":5,"t":"이기는 사람은 이렇게 흰 옷을 입을 것이고, 내가 그 이름을 생명책에서 결코 지우지 않을 것이고, 내 아버지 앞과 그분의 천사들 앞에서 그 이름을 시인하겠다."},{"n":6,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라.\\""},{"n":7,"t":"빌라델비아 교회의 사자에게 편지를 써라. 거룩하시고 참되시며, 다윗의 열쇠를 가지신 분, 곧 열면 아무도 닫을 수 없고, 닫으면 아무도 열 수 없는 분이 이렇게 말씀하세요."},{"n":8,"t":"\\"보아라, 내가 네 앞에 열린 문을 두었는데, 아무도 그것을 닫을 수 없다. 나는 네 행위를 안다. 네가 작은 능력을 가졌으면서도 내 말을 지켰고, 내 이름을 배반하지 않았다."},{"n":9,"t":"보아라, 사탄의 회당, 곧 자칭 유대 사람이라고 하지만 그렇지 않고 거짓말을 하는 사람들 가운데서 몇몇을 네게 주어, 그들이 와서 네 발 앞에 절하게 하고, 내가 너를 사랑한다는 것을 알게 하겠다."},{"n":10,"t":"네가 내 인내의 말씀을 지켰으니, 나도 너를 지켜서, 앞으로 온 세상에 임해서 땅에 거하는 사람들을 시험할 그 시험의 때를 면하게 해 주겠다."},{"n":11,"t":"내가 속히 가겠다. 네가 가진 것을 굳게 붙잡아, 아무도 네 면류관을 빼앗지 못하게 하라."},{"n":12,"t":"이기는 사람은 내가 내 하나님 성전의 기둥이 되게 하겠다. 그는 결코 다시 (성전에서) 나가지 않을 것이다. 내가 그 사람 위에 내 하나님의 이름과, 내 하나님의 성, 곧 하늘에서 내 하나님께로부터 내려오는 새 예루살렘의 이름과, 나의 새 이름을 기록하겠다."},{"n":13,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라.\\""},{"n":14,"t":"라오디게아 교회의 사자에게 편지를 써라. \\"아멘\\"이시고, 신실하고 참된 증인이시고, 하나님의 창조의 근본이신 분이 이렇게 말씀하세요."},{"n":15,"t":"\\"나는 네 행위를 안다. 네가 차지도 않고 뜨겁지도 않다. 네가 차든지 뜨겁든지 하기를 원한다."},{"n":16,"t":"네가 이렇게 미지근하고, 뜨겁지도 차지도 않으니, 내 입에서 너를 토해 내겠다."},{"n":17,"t":"네가 말하기를 \\"나는 부자다. 부요해서 부족한 것이 없다\\"고 하지만, 사실은 네가 비참하고, 가련하고, 가난하고, 눈 멀고, 벌거벗은 자라는 것을 알지 못한다."},{"n":18,"t":"내가 너에게 권한다. 나에게서 불로 단련된 금을 사서 부요해지고, 흰 옷을 사서 입어 벌거벗은 부끄러움이 드러나지 않게 하고, 안약을 사서 눈에 발라 보게 하라."},{"n":19,"t":"내가 사랑하는 사람마다 책망하고 징계한다. 그러므로 너는 열심을 내고, 회개하라."},{"n":20,"t":"보아라, 내가 문 밖에 서서 두드리고 있다. 누구든지 내 음성을 듣고 문을 열면, 내가 그 사람에게로 들어가서 그와 함께 먹고, 그도 나와 함께 먹을 것이다."},{"n":21,"t":"이기는 사람에게는, 내가 이기고 내 아버지의 보좌에 함께 앉은 것처럼, 그도 내 보좌에 나와 함께 앉게 해 주겠다."},{"n":22,"t":"귀 있는 사람은 성령이 교회들에게 하시는 말씀을 들어라.\\""}]}},{"chapter":4,"title":"보좌 앞의 예배","verses":{"krv":[{"n":1,"t":"이 일 후에 내가 보니 하늘에 열린 문이 있는데 내가 들은 바 처음에 내게 말하던 나팔 소리 같은 그 음성이 가로되 이리로 올라오라 이 후에 마땅히 될 일을 내가 네게 보이리라 하시더라"},{"n":2,"t":"내가 곧 성령에 감동하였더니 보라 하늘에 보좌를 베풀었고 그 보좌 위에 앉으신 이가 있는데"},{"n":3,"t":"앉으신 이의 모양이 벽옥과 홍보석 같고 또 무지개가 있어 보좌에 둘렸는데 그 모양이 녹보석 같더라"},{"n":4,"t":"또 보좌에 둘려 이십사 보좌들이 있고 그 보좌들 위에 이십사 장로들이 흰 옷을 입고 머리에 금 면류관을 쓰고 앉았더라"},{"n":5,"t":"보좌로부터 번개와 음성과 뇌성이 나고 보좌 앞에 일곱 등불 켠 것이 있으니 이는 하나님의 일곱 영이라"},{"n":6,"t":"보좌 앞에 수정과 같은 유리 바다가 있고 보좌 가운데와 보좌 주위에 네 생물이 있는데 앞 뒤에 눈이 가득하더라"},{"n":7,"t":"그 첫째 생물은 사자 같고 그 둘째 생물은 송아지 같고 그 셋째 생물은 얼굴이 사람 같고 그 넷째 생물은 날아가는 독수리 같은데"},{"n":8,"t":"네 생물이 각각 여섯 날개가 있고 그 안과 주위에 눈이 가득하더라 그들이 밤낮 쉬지 않고 이르기를 거룩하다 거룩하다 거룩하다 주 하나님 곧 전능하신 이여 전에도 계셨고 이제도 계시고 장차 오실 자라 하고"},{"n":9,"t":"그 생물들이 영광과 존귀와 감사를 보좌에 앉으사 세세토록 사시는 이에게 돌릴 때에"},{"n":10,"t":"이십사 장로들이 보좌에 앉으신 이 앞에 엎드려 세세토록 사시는 이에게 경배하고 자기의 면류관을 보좌 앞에 던지며 가로되"},{"n":11,"t":"우리 주 하나님이여 영광과 존귀와 능력을 받으시는 것이 합당하오니 주께서 만물을 지으신지라 만물이 주의 뜻대로 있었고 또 지으심을 받았나이다 하더라"}],"kids":[{"n":1,"t":"이 일 후에 내가 보니, 하늘에 열린 문이 있었어요. 또 내가 처음에 들었던 나팔 소리 같은 그 음성이 말씀하셨어요. \\"여기로 올라오너라. 앞으로 마땅히 일어날 일들을 내가 네게 보여 주겠다.\\""},{"n":2,"t":"내가 곧 성령에 감동되었어요. 보아라, 하늘에 보좌가 놓여 있고, 그 보좌 위에 한 분이 앉아 계셨어요."},{"n":3,"t":"앉아 계신 분의 모습이 벽옥과 홍보석 같았고, 또 그 보좌 둘레에는 무지개가 있었는데, 그 모습은 녹보석 같았어요."},{"n":4,"t":"또 그 보좌 둘레에 스물네 개의 보좌가 있고, 그 보좌들 위에 스물네 명의 장로가 흰 옷을 입고 머리에 금 면류관을 쓰고 앉아 있었어요."},{"n":5,"t":"보좌에서는 번개와 음성과 천둥이 나오고 있었고, 보좌 앞에는 일곱 개의 등불이 켜져 있었는데, 이것은 하나님의 일곱 영이에요."},{"n":6,"t":"보좌 앞에는 수정과 같은 유리 바다가 있었고, 보좌의 가운데와 보좌 주위에는 네 생물이 있었는데, 앞과 뒤에 눈이 가득했어요."},{"n":7,"t":"그 첫째 생물은 사자 같았고, 둘째 생물은 송아지 같았고, 셋째 생물은 얼굴이 사람 같았고, 넷째 생물은 날아가는 독수리 같았어요."},{"n":8,"t":"네 생물은 각각 여섯 날개를 가지고 있었고, 그 안쪽과 둘레에 눈이 가득했어요. 그들은 밤낮 쉬지 않고 외쳤어요. \\"거룩하다, 거룩하다, 거룩하다, 주 하나님 곧 전능하신 분이시여! 전에도 계셨고, 이제도 계시고, 앞으로 오실 분이시다!\\""},{"n":9,"t":"그 생물들이 보좌에 앉으셔서 영원무궁히 살아 계신 분께 영광과 존귀와 감사를 돌릴 때에,"},{"n":10,"t":"스물네 장로가 보좌에 앉으신 분 앞에 엎드려, 영원무궁히 살아 계신 분께 경배하고, 자기들의 면류관을 보좌 앞에 던지며 외쳤어요."},{"n":11,"t":"\\"우리 주 하나님이시여, 영광과 존귀와 능력을 받으시기에 합당하십니다. 주님께서 만물을 지으셨고, 만물이 주님의 뜻대로 있었고, 또 지으심을 받았기 때문입니다.\\""}]}},{"chapter":5,"title":"어린양과 일곱 인 봉한 책","verses":{"krv":[{"n":1,"t":"내가 보매 보좌에 앉으신 이의 오른손에 책이 있으니 안팎으로 썼고 일곱 인으로 봉하였더라"},{"n":2,"t":"또 보매 힘있는 천사가 큰 음성으로 외치기를 누가 책을 펴며 그 인을 떼기에 합당하냐 하니"},{"n":3,"t":"하늘 위에나 땅 위에나 땅 아래에 능히 책을 펴거나 보거나 할 이가 없더라"},{"n":4,"t":"이 책을 펴거나 보거나 하기에 합당한 자가 보이지 않기로 내가 크게 울었더니"},{"n":5,"t":"장로 중에 하나가 내게 말하되 울지 말라 유대 지파의 사자 다윗의 뿌리가 이기었으니 이 책과 그 일곱 인을 떼시리라 하더라"},{"n":6,"t":"내가 또 보니 보좌와 네 생물과 장로들 사이에 어린 양이 섰는데 일찍 죽임을 당한 것 같더라 일곱 뿔과 일곱 눈이 있으니 이 눈은 온 땅에 보내심을 입은 하나님의 일곱 영이더라"},{"n":7,"t":"어린 양이 나아와서 보좌에 앉으신 이의 오른손에서 책을 취하시니라"},{"n":8,"t":"책을 취하시매 네 생물과 이십사 장로들이 어린 양 앞에 엎드려 각각 거문고와 향이 가득한 금대접을 가졌으니 이 향은 성도의 기도들이라"},{"n":9,"t":"새 노래를 노래하여 가로되 책을 가지시고 그 인봉을 떼기에 합당하시도다 일찍 죽임을 당하사 각 족속과 방언과 백성과 나라 가운데서 사람들을 피로 사서 하나님께 드리시고"},{"n":10,"t":"저희로 우리 하나님 앞에서 나라와 제사장을 삼으셨으니 저희가 땅에서 왕 노릇 하리로다 하더라"},{"n":11,"t":"내가 또 보고 들으매 보좌와 생물들과 장로들을 둘러 선 많은 천사의 음성이 있으니 그 수가 만만이요 천천이라"},{"n":12,"t":"큰 음성으로 가로되 죽임을 당하신 어린 양이 능력과 부와 지혜와 힘과 존귀와 영광과 찬송을 받으시기에 합당하도다 하더라"},{"n":13,"t":"내가 또 들으니 하늘 위에와 땅 위에와 땅 아래와 바다 위에와 또 그 가운데 모든 만물이 가로되 보좌에 앉으신 이와 어린 양에게 찬송과 존귀와 영광과 능력을 세세토록 돌릴지어다 하니"},{"n":14,"t":"네 생물이 가로되 아멘 하고 장로들은 엎드려 경배하더라"}],"kids":[{"n":1,"t":"내가 보니, 보좌에 앉으신 분의 오른손에 책(두루마리)이 있는데, 안팎으로 글이 쓰여 있고 일곱 개의 봉인(도장)으로 봉해져 있었어요."},{"n":2,"t":"또 보니, 힘 있는 천사가 큰 음성으로 외쳤어요. \\"누가 책을 펴고 그 봉인을 뗄 자격이 있는가?\\""},{"n":3,"t":"그러나 하늘 위에서나 땅 위에서나 땅 아래에서나, 아무도 그 책을 펴거나 들여다볼 수 있는 사람이 없었어요."},{"n":4,"t":"이 책을 펴거나 들여다볼 자격이 있는 사람이 보이지 않아서, 내가 크게 울었어요."},{"n":5,"t":"그러자 장로 중 한 명이 내게 말했어요. \\"울지 마세요. 유다 지파의 사자, 다윗의 뿌리가 이기셨어요. 그분이 이 책과 그 일곱 봉인을 떼실 거예요.\\""},{"n":6,"t":"내가 또 보니, 보좌와 네 생물과 장로들 사이에, 어린 양이 서 있었어요. 그 어린 양은 일찍 죽임을 당한 모습이었어요. 그분에게는 일곱 뿔과 일곱 눈이 있었는데, 이 눈은 온 땅에 보내심을 받은 하나님의 일곱 영이었어요."},{"n":7,"t":"어린 양이 나아와서, 보좌에 앉으신 분의 오른손에서 책을 받으셨어요."},{"n":8,"t":"그분이 책을 받으셨을 때, 네 생물과 스물네 장로가 어린 양 앞에 엎드렸어요. 그들은 각각 거문고(수금)와 향이 가득한 금 대접을 가지고 있었는데, 이 향은 성도의 기도들이에요."},{"n":9,"t":"그들은 새 노래를 부르며 외쳤어요. \\"주님께서 그 책을 받으시고 그 봉인을 떼시기에 합당하십니다. 주님께서 일찍 죽임을 당하셔서, 모든 족속과 언어와 백성과 나라 가운데서 사람들을 (주님의) 피로 사서 하나님께 드리셨고,"},{"n":10,"t":"그들을 우리 하나님 앞에서 한 나라와 제사장으로 삼으셨습니다. 그들이 땅에서 왕 노릇 할 것입니다.\\""},{"n":11,"t":"내가 또 보고 들으니, 보좌와 생물들과 장로들 둘레에 서 있는 많은 천사의 음성이 있었어요. 그 수가 수억 만이고 수천 만이었어요."},{"n":12,"t":"그들이 큰 음성으로 외쳤어요. \\"죽임을 당하신 어린 양은, 능력과 부와 지혜와 힘과 존귀와 영광과 찬송을 받으시기에 합당하십니다!\\""},{"n":13,"t":"내가 또 들으니, 하늘 위와 땅 위와 땅 아래와 바다 위, 또 그 안에 있는 모든 만물이 외쳤어요. \\"보좌에 앉으신 분과 어린 양께 찬송과 존귀와 영광과 권능이 영원무궁히 있기를 바랍니다!\\""},{"n":14,"t":"네 생물이 \\"아멘\\" 하고 외쳤고, 장로들은 엎드려 경배했어요."}]}},{"chapter":6,"title":"여섯 인을 떼심","verses":{"krv":[{"n":1,"t":"내가 보매 어린 양이 일곱 인 중에 하나를 떼시는 그 때에 내가 들으니 네 생물 중에 하나가 우뢰 소리 같이 말하되 오라 하기로"},{"n":2,"t":"내가 이에 보니 흰 말이 있는데 그 탄 자가 활을 가졌고 면류관을 받고 나가서 이기고 또 이기려고 하더라"},{"n":3,"t":"둘째 인을 떼실 때에 내가 들으니 둘째 생물이 말하되 오라 하더니"},{"n":4,"t":"이에 붉은 다른 말이 나오더라 그 탄 자가 허락을 받아 땅에서 화평을 제하여 버리며 서로 죽이게 하고 또 큰 칼을 받았더라"},{"n":5,"t":"셋째 인을 떼실 때에 내가 들으니 셋째 생물이 말하되 오라 하기로 내가 보니 검은 말이 나오는데 그 탄 자가 손에 저울을 가졌더라"},{"n":6,"t":"내가 네 생물 사이로서 나는듯하는 음성을 들으니 가로되 한 데나리온에 밀 한 되요 한 데나리온에 보리 석 되로다 또 감람유와 포도주는 해치 말라 하더라"},{"n":7,"t":"넷째 인을 떼실 때에 내가 넷째 생물의 음성을 들으니 가로되 오라 하기로"},{"n":8,"t":"내가 보매 청황색 말이 나오는데 그 탄 자의 이름은 사망이니 음부가 그 뒤를 따르더라 저희가 땅 사분 일의 권세를 얻어 검과 흉년과 사망과 땅의 짐승으로써 죽이더라"},{"n":9,"t":"다섯째 인을 떼실 때에 내가 보니 하나님의 말씀과 저희의 가진 증거를 인하여 죽임을 당한 영혼들이 제단 아래 있어"},{"n":10,"t":"큰 소리로 불러 가로되 거룩하고 참되신 대주재여 땅에 거하는 자들을 심판하여 우리 피를 신원하여 주지 아니하시기를 어느 때까지 하시려나이까 하니"},{"n":11,"t":"각각 저희에게 흰 두루마기를 주시며 가라사대 아직 잠시 동안 쉬되 저희 동무 종들과 형제들도 자기처럼 죽임을 받아 그 수가 차기까지 하라 하시더라"},{"n":12,"t":"내가 보니 여섯째 인을 떼실 때에 큰 지진이 나며 해가 총담 같이 검어지고 온 달이 피 같이 되며"},{"n":13,"t":"하늘의 별들이 무화과나무가 대풍에 흔들려 선 과실이 떨어지는 것 같이 땅에 떨어지며"},{"n":14,"t":"하늘은 종이 축이 말리는 것 같이 떠나가고 각 산과 섬이 제 자리에서 옮기우매"},{"n":15,"t":"땅의 임금들과 왕족들과 장군들과 부자들과 강한 자들과 각 종과 자주자가 굴과 산 바위 틈에 숨어"},{"n":16,"t":"산과 바위에게 이르되 우리 위에 떨어져 보좌에 앉으신 이의 낯에서와 어린 양의 진노에서 우리를 가리우라"},{"n":17,"t":"그들의 진노의 큰 날이 이르렀으니 누가 능히 서리요 하더라"}],"kids":[{"n":1,"t":"내가 보니, 어린 양이 일곱 봉인 중 하나를 떼셨어요. 그때 내가 들으니, 네 생물 중 하나가 천둥소리 같은 음성으로 \\"오라!\\" 하고 말했어요."},{"n":2,"t":"내가 보니, 흰 말 한 마리가 있는데, 그 위에 탄 사람은 활을 가지고 있었어요. 그가 면류관을 받고 나가서, 이기고 또 이기려 하고 있었어요."},{"n":3,"t":"어린 양이 둘째 봉인을 떼셨을 때, 내가 들으니 둘째 생물이 \\"오라!\\" 하고 말했어요."},{"n":4,"t":"그러자 다른 말 한 마리, 곧 붉은 말이 나왔어요. 그 위에 탄 사람은 땅에서 평화를 빼앗아 버리고 사람들이 서로 죽이게 하는 권한을 받았고, 또 큰 칼을 받았어요."},{"n":5,"t":"어린 양이 셋째 봉인을 떼셨을 때, 내가 들으니 셋째 생물이 \\"오라!\\" 하고 말했어요. 내가 보니, 검은 말이 나왔는데, 그 위에 탄 사람이 손에 저울을 가지고 있었어요."},{"n":6,"t":"내가 네 생물 사이에서 나는 듯한 음성을 들었어요. \\"한 데나리온(하루치 품삯)에 밀 한 되, 한 데나리온에 보리 석 되다. 또 올리브유와 포도주는 해치지 마라.\\""},{"n":7,"t":"어린 양이 넷째 봉인을 떼셨을 때, 내가 들으니 넷째 생물의 음성이 \\"오라!\\" 하고 말했어요."},{"n":8,"t":"내가 보니, 청황색(창백한) 말이 나오는데, 그 위에 탄 사람의 이름은 \\"사망\\"이고, \\"음부\\"(죽은 자들의 처소)가 그 뒤를 따르고 있었어요. 그들은 땅의 사분의 일을 다스릴 권세를 받아서, 칼과 흉년과 죽음과 땅의 짐승으로 사람들을 죽이고 있었어요."},{"n":9,"t":"어린 양이 다섯째 봉인을 떼셨을 때, 내가 보니, 하나님의 말씀과 그들이 가졌던 증언 때문에 죽임을 당한 사람들의 영혼들이 제단 아래에 있었어요."},{"n":10,"t":"그들이 큰 소리로 외쳤어요. \\"거룩하시고 참되신 대주재시여, 언제까지 심판을 미루셔서, 땅에 거하는 사람들에게 우리의 피 흘림을 갚아 주지 않으시려는 겁니까?\\""},{"n":11,"t":"그분이 그들 각자에게 흰 두루마기를 주시면서 말씀하셨어요. \\"아직 잠시 동안 쉬어라. 너희와 함께 종 된 동료들과 형제들도 너희처럼 죽임을 받아 그 수가 다 찰 때까지 (기다려라).\\""},{"n":12,"t":"내가 보니, 어린 양이 여섯째 봉인을 떼셨을 때, 큰 지진이 일어났어요. 해가 검은 모포처럼 검어지고, 온 달이 피같이 되었어요."},{"n":13,"t":"하늘의 별들이, 무화과나무가 큰 바람에 흔들려 설익은 열매가 떨어지는 것처럼 땅에 떨어졌어요."},{"n":14,"t":"하늘은 두루마리 종이가 말리는 것처럼 떠나가 버렸고, 모든 산과 섬이 제 자리에서 옮겨졌어요."},{"n":15,"t":"땅의 왕들과 귀족들과 장군들과 부자들과 강한 자들과 모든 종과 자유로운 사람들이, 굴과 산 바위틈에 숨어서,"},{"n":16,"t":"산과 바위들에게 외쳤어요. \\"우리 위에 떨어져서, 보좌에 앉으신 분의 얼굴과 어린 양의 진노에서 우리를 가려 다오."},{"n":17,"t":"그들의 진노의 큰 날이 왔다. 누가 능히 (그 앞에) 설 수 있겠는가?\\""}]}},{"chapter":7,"title":"인 맞은 자와 흰 옷 입은 무리","verses":{"krv":[{"n":1,"t":"이 일 후에 내가 네 천사가 땅 네 모퉁이에 선 것을 보니 땅의 사방의 바람을 붙잡아 바람으로 하여금 땅에나 바다에나 각종 나무에 불지 못하게 하더라"},{"n":2,"t":"또 보매 다른 천사가 살아 계신 하나님의 인을 가지고 해 돋는 데로부터 올라와서 땅과 바다를 해롭게 할 권세를 얻은 네 천사를 향하여 큰 소리로 외쳐"},{"n":3,"t":"가로되 우리가 우리 하나님의 종들의 이마에 인치기까지 땅이나 바다나 나무나 해하지 말라 하더라"},{"n":4,"t":"내가 인 맞은 자의 수를 들으니 이스라엘 자손의 각 지파 중에서 인 맞은 자들이 십사만 사천이니"},{"n":5,"t":"유다 지파 중에 인 맞은 자가 일만 이천이요 르우벤 지파 중에 일만 이천이요 갓 지파 중에 일만 이천이요"},{"n":6,"t":"아셀 지파 중에 일만 이천이요 납달리 지파 중에 일만 이천이요 므낫세 지파 중에 일만 이천이요"},{"n":7,"t":"시므온 지파 중에 일만 이천이요 레위 지파 중에 일만 이천이요 잇사갈 지파 중에 일만 이천이요"},{"n":8,"t":"스블론 지파 중에 일만 이천이요 요셉 지파 중에 일만 이천이요 베냐민 지파 중에 인 맞은 자가 일만 이천이라"},{"n":9,"t":"이 일 후에 내가 보니 각 나라와 족속과 백성과 방언에서 아무라도 능히 셀 수 없는 큰 무리가 흰 옷을 입고 손에 종려 가지를 들고 보좌 앞과 어린 양 앞에 서서"},{"n":10,"t":"큰 소리로 외쳐 가로되 구원하심이 보좌에 앉으신 우리 하나님과 어린 양에게 있도다 하니"},{"n":11,"t":"모든 천사가 보좌와 장로들과 네 생물의 주위에 섰다가 보좌 앞에 엎드려 얼굴을 대고 하나님께 경배하여"},{"n":12,"t":"가로되 아멘 찬송과 영광과 지혜와 감사와 존귀와 능력과 힘이 우리 하나님께 세세토록 있을지로다 아멘 하더라"},{"n":13,"t":"장로 중에 하나가 응답하여 내게 이르되 이 흰 옷 입은 자들이 누구며 또 어디서 왔느뇨"},{"n":14,"t":"내가 가로되 내 주여 당신이 알리이다 하니 그가 나더러 이르되 이는 큰 환난에서 나오는 자들인데 어린 양의 피에 그 옷을 씻어 희게 하였느니라"},{"n":15,"t":"그러므로 그들이 하나님의 보좌 앞에 있고 또 그의 성전에서 밤낮 하나님을 섬기매 보좌에 앉으신 이가 그들 위에 장막을 치시리니"},{"n":16,"t":"저희가 다시 주리지도 아니하며 목마르지도 아니하고 해나 아무 뜨거운 기운에 상하지 아니할지니"},{"n":17,"t":"이는 보좌 가운데 계신 어린 양이 저희의 목자가 되사 생명수 샘으로 인도하시고 하나님께서 저희 눈에서 모든 눈물을 씻어 주실 것임이러라"}],"kids":[{"n":1,"t":"이 일 후에 내가 보니, 네 천사가 땅의 네 모퉁이에 서 있었어요. 그들은 땅의 사방에서 부는 바람을 붙잡아서, 그 바람이 땅이나 바다나 어떤 나무에도 불지 못하게 하고 있었어요."},{"n":2,"t":"또 내가 보니, 다른 천사 하나가 살아 계신 하나님의 인(도장)을 가지고 해 돋는 곳으로부터 올라와서, 땅과 바다를 해할 권세를 받은 네 천사를 향해 큰 소리로 외쳤어요."},{"n":3,"t":"\\"우리가 우리 하나님의 종들의 이마에 인을 칠 때까지, 땅이나 바다나 나무를 해치지 마라.\\""},{"n":4,"t":"내가 인 침을 받은 사람들의 수를 들으니, 이스라엘 자손 모든 지파 가운데서 인 침을 받은 사람들이 14만 4천 명이었어요."},{"n":5,"t":"유다 지파에서 인 침을 받은 사람이 12,000명이고, 르우벤 지파에서 12,000명이고, 갓 지파에서 12,000명이고,"},{"n":6,"t":"아셀 지파에서 12,000명이고, 납달리 지파에서 12,000명이고, 므낫세 지파에서 12,000명이고,"},{"n":7,"t":"시므온 지파에서 12,000명이고, 레위 지파에서 12,000명이고, 잇사갈 지파에서 12,000명이고,"},{"n":8,"t":"스불론 지파에서 12,000명이고, 요셉 지파에서 12,000명이고, 베냐민 지파에서 인 침을 받은 사람이 12,000명이었어요."},{"n":9,"t":"이 일 후에 내가 보니, 모든 나라와 족속과 백성과 언어에서 나온, 아무도 셀 수 없는 큰 무리가 흰 옷을 입고 손에 종려나무 가지를 들고서, 보좌 앞과 어린 양 앞에 서 있었어요."},{"n":10,"t":"그들이 큰 소리로 외쳤어요. \\"구원이 보좌에 앉으신 우리 하나님과 어린 양께 있습니다!\\""},{"n":11,"t":"모든 천사가 보좌와 장로들과 네 생물 둘레에 서 있다가, 보좌 앞에 얼굴을 대고 엎드려 하나님께 경배하며"},{"n":12,"t":"외쳤어요. \\"아멘! 찬송과 영광과 지혜와 감사와 존귀와 권능과 힘이 우리 하나님께 영원무궁히 있기를 빕니다. 아멘!\\""},{"n":13,"t":"장로 중 한 명이 내게 물었어요. \\"이 흰 옷을 입은 사람들이 누구이고, 어디서 왔습니까?\\""},{"n":14,"t":"내가 대답했어요. \\"내 주여, 당신이 아십니다.\\" 그러자 그가 내게 말했어요. \\"이들은 큰 환난에서 나오는 사람들이고, 어린 양의 피에 자기들의 옷을 씻어 희게 한 사람들이에요."},{"n":15,"t":"그러므로 그들이 하나님의 보좌 앞에 있고, 또 그분의 성전에서 밤낮 하나님을 섬겨요. 보좌에 앉으신 분이 그들 위에 장막을 치고 함께 거하실 거예요."},{"n":16,"t":"그들은 다시는 주리지도 않고 목마르지도 않을 것이고, 해나 어떤 뜨거운 기운에도 상하지 않을 거예요."},{"n":17,"t":"보좌 가운데 계신 어린 양이 그들의 목자가 되시고, 그들을 생명수의 샘으로 인도하시고, 하나님께서 그들의 눈에서 모든 눈물을 씻어 주실 것이기 때문이에요.\\""}]}},{"chapter":8,"title":"일곱 째 인과 네 나팔","verses":{"krv":[{"n":1,"t":"일곱째 인을 떼실 때에 하늘이 반 시 동안쯤 고요하더니"},{"n":2,"t":"내가 보매 하나님 앞에 시위한 일곱 천사가 있어 일곱 나팔을 받았더라"},{"n":3,"t":"또 다른 천사가 와서 제단 곁에 서서 금 향로를 가지고 많은 향을 받았으니 이는 모든 성도의 기도들과 합하여 보좌 앞 금단에 드리고자 함이라"},{"n":4,"t":"향연이 성도의 기도와 함께 천사의 손으로부터 하나님 앞으로 올라가는지라"},{"n":5,"t":"천사가 향로를 가지고 단 위의 불을 담아다가 땅에 쏟으매 뇌성과 음성과 번개와 지진이 나더라"},{"n":6,"t":"일곱 나팔 가진 일곱 천사가 나팔 불기를 예비하더라"},{"n":7,"t":"첫째 천사가 나팔을 부니 피 섞인 우박과 불이 나서 땅에 쏟아지매 땅의 삼분의 일이 타서 사위고 수목의 삼분의 일도 타서 사위고 각종 푸른 풀도 타서 사위더라"},{"n":8,"t":"둘째 천사가 나팔을 부니 불붙는 큰 산과 같은 것이 바다에 던지우매 바다의 삼분의 일이 피가 되고"},{"n":9,"t":"바다 가운데 생명 가진 피조물들의 삼분의 일이 죽고 배들의 삼분의 일이 깨어지더라"},{"n":10,"t":"셋째 천사가 나팔을 부니 횃불 같이 타는 큰 별이 하늘에서 떨어져 강들의 삼분의 일과 여러 물샘에 떨어지니"},{"n":11,"t":"이 별 이름은 쑥이라 물들의 삼분의 일이 쑥이 되매 그 물들이 쓰게 됨을 인하여 많은 사람이 죽더라"},{"n":12,"t":"넷째 천사가 나팔을 부니 해 삼분의 일과 달 삼분의 일과 별들의 삼분의 일이 침을 받아 그 삼분의 일이 어두워지니 낮 삼분의 일은 비췸이 없고 밤도 그러하더라"},{"n":13,"t":"내가 또 보고 들으니 공중에 날아가는 독수리가 큰 소리로 이르되 땅에 거하는 자들에게 화, 화, 화가 있으리로다 이 외에도 세 천사의 불 나팔 소리를 인함이로다 하더라"}],"kids":[{"n":1,"t":"어린 양이 일곱째 봉인을 떼셨을 때, 하늘이 반 시간쯤 조용해졌어요."},{"n":2,"t":"내가 보니, 하나님 앞에 늘 서서 모시는 일곱 천사가 있었는데, 그들이 일곱 나팔을 받았어요."},{"n":3,"t":"또 다른 천사가 와서 제단 곁에 서서 금 향로를 들고 있었어요. 그가 많은 향을 받았는데, 이것은 모든 성도의 기도와 함께 보좌 앞에 있는 금 제단에 드리려는 거였어요."},{"n":4,"t":"향의 연기가 성도들의 기도와 함께 천사의 손에서 하나님 앞으로 올라갔어요."},{"n":5,"t":"그 천사가 향로를 가지고 제단 위의 불을 담아서 땅에 쏟았어요. 그러자 천둥과 음성과 번개와 지진이 일어났어요."},{"n":6,"t":"일곱 나팔을 가진 일곱 천사가 나팔을 불 준비를 했어요."},{"n":7,"t":"첫째 천사가 나팔을 부니, 피가 섞인 우박과 불이 일어나서 땅에 쏟아졌어요. 그러자 땅의 3분의 1이 타 버렸고, 나무의 3분의 1도 타 버렸고, 모든 푸른 풀도 타 버렸어요."},{"n":8,"t":"둘째 천사가 나팔을 부니, 불타는 큰 산 같은 것이 바다에 던져졌어요. 그러자 바다의 3분의 1이 피가 되었고,"},{"n":9,"t":"바다 안에 있는 생명을 가진 피조물의 3분의 1이 죽었고, 배의 3분의 1이 부서졌어요."},{"n":10,"t":"셋째 천사가 나팔을 부니, 횃불처럼 타는 큰 별이 하늘에서 떨어져, 강들의 3분의 1과 여러 샘물에 떨어졌어요."},{"n":11,"t":"이 별의 이름은 \\"쑥(독한 쓴풀)\\"이에요. 그래서 물들의 3분의 1이 쑥처럼 쓰게 되었고, 그 쓴 물 때문에 많은 사람이 죽었어요."},{"n":12,"t":"넷째 천사가 나팔을 부니, 해의 3분의 1과 달의 3분의 1과 별들의 3분의 1이 (해를) 받아서, 그것들의 3분의 1이 어두워졌어요. 그래서 낮의 3분의 1은 빛이 없었고, 밤도 그러했어요."},{"n":13,"t":"내가 또 보고 들으니, 공중에 날아가는 독수리가 큰 소리로 외쳤어요. \\"화가 있다, 화가 있다, 화가 있다, 땅에 거하는 사람들에게! 또 세 천사가 나머지 나팔을 불 때 일어날 일들 때문에!\\""}]}},{"chapter":9,"title":"다섯·여섯 째 나팔","verses":{"krv":[{"n":1,"t":"다섯째 천사가 나팔을 불매 내가 보니 하늘에서 땅에 떨어진 별 하나가 있는데 저가 무저갱의 열쇠를 받았더라"},{"n":2,"t":"저가 무저갱을 여니 그 구멍에서 큰 풀무의 연기 같은 연기가 올라오매 해와 공기가 그 구멍의 연기로 인하여 어두워지며"},{"n":3,"t":"또 황충이 연기 가운데로부터 땅 위에 나오매 저희가 땅에 있는 전갈의 권세와 같은 권세를 받았더라"},{"n":4,"t":"저희에게 이르시되 땅의 풀이나 푸른 것이나 각종 수목은 해하지 말고 오직 이마에 하나님의 인 맞지 아니한 사람들만 해하라 하시더라"},{"n":5,"t":"그러나 그들을 죽이지는 못하게 하시고 다섯 달 동안 괴롭게만 하게 하시는데 그 괴롭게 함은 전갈이 사람을 쏠 때에 괴롭게 함과 같더라"},{"n":6,"t":"그 날에는 사람들이 죽기를 구하여도 얻지 못하고 죽고 싶으나 죽음이 저희를 피하리로다"},{"n":7,"t":"황충들의 모양은 전쟁을 위하여 예비한 말들 같고 그 머리에 금 같은 면류관 비슷한 것을 썼으며 그 얼굴은 사람의 얼굴 같고"},{"n":8,"t":"또 여자의 머리털 같은 머리털이 있고 그 이는 사자의 이 같으며"},{"n":9,"t":"또 철흉갑 같은 흉갑이 있고 그 날개들의 소리는 병거와 많은 말들이 전장으로 달려 들어가는 소리 같으며"},{"n":10,"t":"또 전갈과 같은 꼬리와 쏘는 살이 있어 그 꼬리에는 다섯 달 동안 사람들을 해하는 권세가 있더라"},{"n":11,"t":"저희에게 임금이 있으니 무저갱의 사자라 히브리 음으로 이름은 아바돈이요 헬라 음으로 이름은 아볼루온이더라"},{"n":12,"t":"첫째 화는 지나갔으나 보라 아직도 이 후에 화 둘이 이르리로다"},{"n":13,"t":"여섯째 천사가 나팔을 불매 내가 들으니 하나님 앞 금단 네 뿔에서 한 음성이 나서"},{"n":14,"t":"나팔 가진 여섯째 천사에게 말하기를 큰 강 유브라데에 결박한 네 천사를 놓아 주라 하매"},{"n":15,"t":"네 천사가 놓였으니 그들은 그 년 월 일 시에 이르러 사람 삼분의 일을 죽이기로 예비한 자들이더라"},{"n":16,"t":"마병대의 수는 이만 만이니 내가 그들의 수를 들었노라"},{"n":17,"t":"이같이 이상한 가운데 그 말들과 그 탄 자들을 보니 불빛과 자주빛과 유황빛 흉갑이 있고 또 말들의 머리는 사자 머리 같고 그 입에서는 불과 연기와 유황이 나오더라"},{"n":18,"t":"이 세 재앙 곧 저희 입에서 나오는 불과 연기와 유황을 인하여 사람 삼분의 일이 죽임을 당하니라"},{"n":19,"t":"이 말들의 힘은 그 입과 그 꼬리에 있으니 그 꼬리는 뱀 같고 또 꼬리에 머리가 있어 이것으로 해하더라"},{"n":20,"t":"이 재앙에 죽지 않고 남은 사람들은 그 손으로 행하는 일을 회개치 아니하고 오히려 여러 귀신과 또는 보거나 듣거나 다니거나 하지 못하는 금, 은, 동과 목석의 우상에게 절하고"},{"n":21,"t":"또 그 살인과 복술과 음행과 도적질을 회개치 아니하더라"}],"kids":[{"n":1,"t":"다섯째 천사가 나팔을 부니, 내가 보니 하늘에서 땅에 떨어진 별 하나가 있었어요. 그 별은 무저갱(끝없이 깊은 구덩이)의 열쇠를 받았어요."},{"n":2,"t":"그가 무저갱을 여니, 그 구멍에서 큰 풀무의 연기 같은 연기가 올라왔어요. 해와 공기가 그 구멍의 연기 때문에 어두워졌어요."},{"n":3,"t":"또 메뚜기 떼가 연기 가운데서 나와 땅 위로 나왔는데, 그것들은 땅에 있는 전갈의 권세 같은 권세를 받았어요."},{"n":4,"t":"또 그것들에게 이런 명령이 내려졌어요. \\"땅의 풀이나 푸른 것이나 어떤 나무도 해하지 말고, 오직 이마에 하나님의 인을 받지 않은 사람들만 해하라.\\""},{"n":5,"t":"그러나 그들을 죽이지는 못하게 하시고, 다섯 달 동안 괴롭게만 하게 하셨어요. 그 괴롭게 함은 전갈이 사람을 쏠 때처럼 괴롭게 하는 거였어요."},{"n":6,"t":"그 날에는 사람들이 죽기를 구해도 얻지 못하고, 죽고 싶어 해도 죽음이 그들을 피해 갈 거예요."},{"n":7,"t":"메뚜기들의 모양은 전쟁을 위해 준비된 말들 같았고, 그 머리에 금 같은 면류관 비슷한 것을 쓰고 있었고, 얼굴은 사람의 얼굴 같았어요."},{"n":8,"t":"또 여자의 머리털 같은 머리털이 있었고, 이빨은 사자의 이빨 같았어요."},{"n":9,"t":"또 철 갑옷 같은 흉갑(가슴 보호대)을 입고 있었고, 그 날개의 소리는 병거(전차)들과 많은 말들이 전장으로 달려가는 소리 같았어요."},{"n":10,"t":"또 전갈과 같은 꼬리와 침이 있었고, 그 꼬리에는 다섯 달 동안 사람들을 해할 권세가 있었어요."},{"n":11,"t":"그것들에게 왕이 있었는데, 그는 무저갱의 사자(천사)예요. 히브리어 이름은 \\"아바돈\\"이고, 헬라어 이름은 \\"아볼루온\\"이에요. (이 이름들은 \\"멸망시키는 자\\"라는 뜻이에요.)"},{"n":12,"t":"첫째 화는 지나갔지만, 보아라, 이 후에 아직 두 가지 화가 더 다가오고 있어요."},{"n":13,"t":"여섯째 천사가 나팔을 부니, 내가 들으니, 하나님 앞 금 제단의 네 뿔에서 한 음성이 나서,"},{"n":14,"t":"나팔을 가진 여섯째 천사에게 말했어요. \\"큰 강 유브라데에 결박된 네 천사를 풀어 놓아라.\\""},{"n":15,"t":"네 천사가 풀려났는데, 그들은 그 정해진 년, 월, 일, 시에 사람의 3분의 1을 죽이려고 준비된 자들이었어요."},{"n":16,"t":"기마병들의 수는 2억이었어요. 내가 그들의 수를 들었어요."},{"n":17,"t":"내가 환상 가운데 그 말들과 그 위에 탄 사람들을 보니, 그들은 불빛과 자줏빛과 유황빛 흉갑을 입고 있었고, 말들의 머리는 사자의 머리 같았고, 그 입에서 불과 연기와 유황이 나왔어요."},{"n":18,"t":"이 세 가지 재앙, 곧 그들의 입에서 나오는 불과 연기와 유황으로 인해 사람의 3분의 1이 죽임을 당했어요."},{"n":19,"t":"이 말들의 힘은 그 입과 그 꼬리에 있었어요. 그 꼬리는 뱀 같았고, 꼬리에 머리가 있어서 그것으로 사람들을 해쳤어요."},{"n":20,"t":"이 재앙들에서 죽지 않고 살아남은 사람들은, 자기 손으로 한 일을 회개하지 않았고, 오히려 여러 귀신들과, 또 보지도 듣지도 걷지도 못하는 금, 은, 동, 돌, 나무로 만든 우상들에게 절하기를 그치지 않았고,"},{"n":21,"t":"또 자기들의 살인과 마술과 음란한 짓과 도둑질을 회개하지 않았어요."}]}},{"chapter":10,"title":"작은 두루마리","verses":{"krv":[{"n":1,"t":"내가 또 보니 힘센 다른 천사가 구름을 입고 하늘에서 내려오는데 그 머리 위에 무지개가 있고 그 얼굴은 해 같고 그 발은 불기둥 같으며"},{"n":2,"t":"그 손에 펴 놓인 작은 책을 들고 그 오른발은 바다를 밟고 왼발은 땅을 밟고"},{"n":3,"t":"사자의 부르짖는 것 같이 큰 소리로 외치니 외칠 때에 일곱 우뢰가 그 소리를 발하더라"},{"n":4,"t":"일곱 우뢰가 발할 때에 내가 기록하려고 하다가 곧 들으니 하늘에서 소리 나서 말하기를 일곱 우뢰가 발한 것을 인봉하고 기록하지 말라 하더라"},{"n":5,"t":"내가 본 바 바다와 땅을 밟고 섰는 천사가 하늘을 향하여 오른손을 들고"},{"n":6,"t":"세세토록 살아계신 자 곧 하늘과 그 가운데 있는 물건이며 땅과 그 가운데 있는 물건이며 바다와 그 가운데 있는 물건을 창조하신 이를 가리켜 맹세하여 가로되 지체하지 아니하리니"},{"n":7,"t":"일곱째 천사가 소리 내는 날 그 나팔을 불게 될 때에 하나님의 비밀이 그 종 선지자들에게 전하신 복음과 같이 이루리라"},{"n":8,"t":"하늘에서 나서 내게 들리던 음성이 또 내게 말하여 가로되 네가 가서 바다와 땅을 밟고 섰는 천사의 손에 펴 놓인 책을 가지라 하기로"},{"n":9,"t":"내가 천사에게 나아가 작은 책을 달라 한즉 천사가 가로되 갖다 먹어버리라 네 배에는 쓰나 네 입에는 꿀 같이 달리라 하거늘"},{"n":10,"t":"내가 천사의 손에서 작은 책을 갖다 먹어버리니 내 입에는 꿀 같이 다나 먹은 후에 내 배에서는 쓰게 되더라"},{"n":11,"t":"저가 내게 말하기를 네가 많은 백성과 나라와 방언과 임금에게 다시 예언하여야 하리라 하더라"}],"kids":[{"n":1,"t":"내가 또 보니, 힘센 다른 천사가 구름을 옷처럼 입고 하늘에서 내려오고 있었어요. 그 머리 위에는 무지개가 있고, 얼굴은 해 같고, 발은 불기둥 같았어요."},{"n":2,"t":"그 손에는 펴진 작은 두루마리(책)가 있었고, 오른발은 바다를 밟고 왼발은 땅을 밟고 있었어요."},{"n":3,"t":"그가 사자가 부르짖는 것처럼 큰 소리로 외쳤어요. 그가 외치자, 일곱 천둥이 그 소리를 냈어요."},{"n":4,"t":"일곱 천둥이 소리를 냈을 때, 내가 기록하려 하자, 하늘에서 음성이 들려왔어요. \\"일곱 천둥이 말한 것은 봉인하고 기록하지 마라.\\""},{"n":5,"t":"내가 보니, 바다와 땅을 밟고 서 있는 그 천사가 하늘을 향해 오른손을 들었어요."},{"n":6,"t":"그가 영원무궁히 살아 계신 분, 곧 하늘과 그 안에 있는 모든 것, 땅과 그 안에 있는 모든 것, 바다와 그 안에 있는 모든 것을 창조하신 분을 가리켜 맹세하며 말했어요. \\"더 이상 지체되지 않을 것이다."},{"n":7,"t":"일곱째 천사가 나팔을 부는 날에, 그 나팔이 불릴 때에, 하나님께서 그 종 예언자들에게 전하신 복음(좋은 소식)대로 하나님의 비밀이 이루어질 것이다.\\""},{"n":8,"t":"하늘에서 나서 내게 들리던 그 음성이 또 내게 말씀하셨어요. \\"네가 가서, 바다와 땅을 밟고 서 있는 그 천사의 손에 펴진 책을 받아 가져라.\\""},{"n":9,"t":"내가 그 천사에게 나아가서 작은 책을 달라고 했어요. 그러자 천사가 말했어요. \\"가져다 먹어 버려라. 네 배에는 쓰지만, 네 입에는 꿀처럼 달 것이다.\\""},{"n":10,"t":"내가 그 천사의 손에서 작은 책을 받아 먹어 버리니, 내 입에는 꿀처럼 달았지만, 먹은 뒤에는 내 배에서 쓰게 되었어요."},{"n":11,"t":"그가 내게 말했어요. \\"너는 많은 백성과 나라와 언어와 왕들에 대해 다시 예언해야 한다.\\""}]}},{"chapter":11,"title":"두 증인","verses":{"krv":[{"n":1,"t":"또 내게 지팡이 같은 갈대를 주며 말하기를 일어나서 하나님의 성전과 제단과 그 안에서 경배하는 자들을 척량하되"},{"n":2,"t":"성전 밖 마당은 척량하지 말고 그냥 두라 이것을 이방인에게 주었은즉 저희가 거룩한 성을 마흔두 달 동안 짓밟으리라"},{"n":3,"t":"내가 나의 두 증인에게 권세를 주리니 저희가 굵은 베옷을 입고 일천이백육십 일을 예언하리라"},{"n":4,"t":"이는 이 땅의 주 앞에 섰는 두 감람나무와 두 촛대니"},{"n":5,"t":"만일 누구든지 저희를 해하고자 한즉 저희 입에서 불이 나서 그 원수를 소멸할지니 누구든지 해하려 하면 반드시 이와 같이 죽임을 당하리라"},{"n":6,"t":"저희가 권세를 가지고 하늘을 닫아 그 예언을 하는 날 동안 비 오지 못하게 하고 또 권세를 가지고 물을 변하여 피 되게 하고 아무 때든지 원하는 대로 여러 가지 재앙으로 땅을 치리로다"},{"n":7,"t":"저희가 그 증거를 마칠 때에 무저갱으로부터 올라오는 짐승이 저희로 더불어 전쟁을 일으켜 저희를 이기고 저희를 죽일 터인즉"},{"n":8,"t":"저희 시체가 큰 성 길에 있으리니 그 성은 영적으로 하면 소돔이라고도 하고 애굽이라고도 하니 곧 저희 주께서 십자가에 못 박히신 곳이니라"},{"n":9,"t":"백성들과 족속과 방언과 나라 중에서 사람들이 그 시체를 사흘 반 동안을 목도하며 무덤에 장사하지 못하게 하리로다"},{"n":10,"t":"이 두 선지자가 땅에 거하는 자들을 괴롭게 한 고로 땅에 거하는 자들이 저희의 죽음을 즐거워하고 기뻐하여 서로 예물을 보내리라 하더라"},{"n":11,"t":"삼 일 반 후에 하나님께로부터 생기가 저희 속에 들어가매 저희 발로 일어서니 구경하는 자들이 크게 두려워하더라"},{"n":12,"t":"하늘로부터 큰 음성이 있어 이리로 올라오라 함을 저희가 듣고 구름을 타고 하늘로 올라가니 저희 원수들도 구경하더라"},{"n":13,"t":"그 시에 큰 지진이 나서 성 십분의 일이 무너지고 지진에 죽은 사람이 칠천이라 그 남은 자들이 두려워하여 영광을 하늘의 하나님께 돌리더라"},{"n":14,"t":"둘째 화는 지나갔으나 보라 셋째 화가 속히 이르는도다"},{"n":15,"t":"일곱째 천사가 나팔을 불매 하늘에 큰 음성들이 나서 가로되 세상 나라가 우리 주와 그 그리스도의 나라가 되어 그가 세세토록 왕 노릇 하시리로다 하니"},{"n":16,"t":"하나님 앞에 자기 보좌에 앉은 이십사 장로들이 엎드려 얼굴을 대고 하나님께 경배하여"},{"n":17,"t":"가로되 감사하옵나니 옛적에도 계셨고 시방도 계신 주 하나님 곧 전능하신 이여 친히 큰 권능을 잡으시고 왕 노릇 하시도다"},{"n":18,"t":"이방들이 분노하매 주의 진노가 임하여 죽은 자를 심판하시며 종 선지자들과 성도들과 또 무론대소하고 주의 이름을 경외하는 자들에게 상 주시며 또 땅을 망하게 하는 자들을 멸망시키실 때로소이다 하더라"},{"n":19,"t":"이에 하늘에 있는 하나님의 성전이 열리니 성전 안에 하나님의 언약궤가 보이며 또 번개와 음성들과 뇌성과 지진과 큰 우박이 있더라"}],"kids":[{"n":1,"t":"또 그가 내게 지팡이 같은 갈대를 주면서 말했어요. \\"일어나서 하나님의 성전과 제단과 그 안에서 경배하는 사람들을 측량하라."},{"n":2,"t":"그러나 성전 바깥 마당은 측량하지 말고 그대로 두어라. 그것은 이방 사람들에게 내주어졌으니, 그들이 거룩한 성을 마흔두 달 동안 짓밟을 것이다."},{"n":3,"t":"내가 나의 두 증인에게 권세를 줄 것이고, 그들은 굵은 베옷을 입고 1,260일 동안 예언할 것이다.\\""},{"n":4,"t":"이들은 이 땅의 주님 앞에 서 있는 두 감람나무이고 두 촛대예요."},{"n":5,"t":"만약 누구든지 그들을 해하려고 하면, 그들의 입에서 불이 나서 그 원수를 태워 버릴 거예요. 누구든지 그들을 해하려는 사람은, 반드시 이렇게 죽임을 당할 거예요."},{"n":6,"t":"그들은 권세를 가지고 하늘을 닫아서, 그들이 예언하는 날 동안에 비가 내리지 못하게 하고, 또 권세를 가지고 물을 피로 변하게 하고, 언제든지 원하는 대로 여러 가지 재앙으로 땅을 칠 수 있어요."},{"n":7,"t":"그들이 자기들의 증언을 마쳤을 때, 무저갱(끝없이 깊은 구덩이)에서 올라오는 짐승이 그들과 전쟁을 일으켜 그들을 이기고 그들을 죽일 거예요."},{"n":8,"t":"그들의 시체는 큰 성의 길거리에 놓여 있을 거예요. 그 성은 영적인 의미로 \\"소돔\\"이라고도 하고 \\"이집트\\"라고도 하는데, 곧 그들의 주님이 십자가에 못 박히신 곳이에요."},{"n":9,"t":"백성들과 족속과 언어와 나라 가운데서 사람들이 그 시체를 사흘 반 동안 바라볼 것이고, 그 시체를 무덤에 묻지 못하게 할 거예요."},{"n":10,"t":"이 두 예언자가 땅에 거하는 사람들을 괴롭게 했기 때문에, 땅에 거하는 사람들이 그들의 죽음을 즐거워하고 기뻐하면서 서로 선물을 주고받을 거예요."},{"n":11,"t":"그러나 사흘 반 후에, 하나님께로부터 생명의 기운이 그들 안으로 들어가서, 그들이 발로 일어섰어요. 그것을 구경하던 사람들이 크게 두려워했어요."},{"n":12,"t":"또 하늘로부터 큰 음성이 있었어요. \\"이리로 올라오너라.\\" 그들이 그 음성을 듣고 구름을 타고 하늘로 올라갔고, 그들의 원수들도 그것을 보았어요."},{"n":13,"t":"그 시간에 큰 지진이 일어나서 성의 10분의 1이 무너졌고, 지진으로 죽은 사람이 7,000명이었어요. 살아남은 사람들은 두려워하여 하늘의 하나님께 영광을 돌렸어요."},{"n":14,"t":"둘째 화는 지나갔지만, 보아라, 셋째 화가 속히 다가오고 있어요."},{"n":15,"t":"일곱째 천사가 나팔을 부니, 하늘에서 큰 음성들이 나서 외쳤어요. \\"세상의 나라가 우리 주님과 그분의 그리스도의 나라가 되었다. 그분이 영원무궁히 왕으로 다스리실 것이다!\\""},{"n":16,"t":"하나님 앞에 자기 보좌에 앉아 있던 스물네 장로가, 얼굴을 대고 엎드려 하나님께 경배하며"},{"n":17,"t":"외쳤어요. \\"감사합니다. 옛부터 계셨고 지금도 계신 주 하나님, 곧 전능하신 분이시여! 친히 큰 권능을 잡으시고 왕으로 다스리시는군요."},{"n":18,"t":"이방 민족들이 분노했지만, 주님의 진노가 임해서 죽은 사람들을 심판하실 때가, 또 주님의 종인 예언자들과 성도들과, 작든 크든 주님의 이름을 경외하는 사람들에게 상을 주실 때가, 또 땅을 망하게 하는 자들을 멸망시키실 때가 왔습니다.\\""},{"n":19,"t":"그때 하늘에 있는 하나님의 성전이 열렸고, 그 성전 안에 하나님의 언약궤가 보였어요. 또 번개와 음성들과 천둥과 지진과 큰 우박이 있었어요."}]}},{"chapter":12,"title":"여자와 용","verses":{"krv":[{"n":1,"t":"하늘에 큰 이적이 보이니 해를 입은 한 여자가 있는데 그 발 아래는 달이 있고 그 머리에는 열두 별의 면류관을 썼더라"},{"n":2,"t":"이 여자가 아이를 배어 해산하게 되매 아파서 애써 부르짖더라"},{"n":3,"t":"하늘에 또 다른 이적이 보이니 보라 한 큰 붉은 용이 있어 머리가 일곱이요 뿔이 열이라 그 여러 머리에 일곱 면류관이 있는데"},{"n":4,"t":"그 꼬리가 하늘 별 삼분의 일을 끌어다가 땅에 던지더라 용이 해산하려는 여자 앞에서 그가 해산하면 그 아이를 삼키고자 하더니"},{"n":5,"t":"여자가 아들을 낳으니 이는 장차 철장으로 만국을 다스릴 남자라 그 아이를 하나님 앞과 그 보좌 앞으로 올려가더라"},{"n":6,"t":"그 여자가 광야로 도망하매 거기서 일천이백육십 일 동안 저를 양육하기 위하여 하나님의 예비하신 곳이 있더라"},{"n":7,"t":"하늘에 전쟁이 있으니 미가엘과 그의 사자들이 용으로 더불어 싸울새 용과 그의 사자들도 싸우나"},{"n":8,"t":"이기지 못하여 다시 하늘에서 저희의 있을 곳을 얻지 못한지라"},{"n":9,"t":"큰 용이 내어 쫓기니 옛 뱀 곧 마귀라고도 하고 사단이라고도 하는 온 천하를 꾀는 자라 땅으로 내어 쫓기니 그의 사자들도 저와 함께 내어 쫓기니라"},{"n":10,"t":"내가 또 들으니 하늘에 큰 음성이 있어 가로되 이제 우리 하나님의 구원과 능력과 나라와 또 그의 그리스도의 권세가 이루었으니 우리 형제들을 참소하던 자 곧 우리 하나님 앞에서 밤낮 참소하던 자가 쫓겨났고"},{"n":11,"t":"또 여러 형제가 어린 양의 피와 자기의 증거하는 말을 인하여 저를 이기었으니 그들은 죽기까지 자기 생명을 아끼지 아니하였도다"},{"n":12,"t":"그러므로 하늘과 그 가운데 거하는 자들은 즐거워하라 그러나 땅과 바다는 화 있을진저 이는 마귀가 자기의 때가 얼마 못된 줄을 알므로 크게 분내어 너희에게 내려갔음이라 하더라"},{"n":13,"t":"용이 자기가 땅으로 내어 쫓긴 것을 보고 남자를 낳은 여자를 핍박하는지라"},{"n":14,"t":"그 여자가 큰 독수리의 두 날개를 받아 광야 자기 곳으로 날아가 거기서 그 뱀의 낯을 피하여 한 때와 두 때와 반 때를 양육 받으매"},{"n":15,"t":"여자의 뒤에서 뱀이 그 입으로 물을 강 같이 토하여 여자를 물에 떠내려 가게 하려 하되"},{"n":16,"t":"땅이 여자를 도와 그 입을 벌려 용의 입에서 토한 강물을 삼키니"},{"n":17,"t":"용이 여자에게 분노하여 돌아가서 그 여자의 남은 자손 곧 하나님의 계명을 지키며 예수의 증거를 가진 자들로 더불어 싸우려고 바다 모래 위에 섰더라"},{"n":18,"t":""}],"kids":[{"n":1,"t":"하늘에 큰 표징이 보였어요. 한 여자가 해를 옷처럼 입고 있는데, 발 아래에는 달이 있었고, 머리에는 열두 별로 된 면류관을 쓰고 있었어요."},{"n":2,"t":"이 여자는 아이를 배고 있었는데, 해산할 때가 되어 아파서 애써 소리를 질렀어요."},{"n":3,"t":"하늘에 또 다른 표징이 보였어요. 보아라, 한 큰 붉은 용이 있는데, 머리가 일곱이고 뿔이 열이며, 그 여러 머리에 일곱 면류관을 쓰고 있었어요."},{"n":4,"t":"그 꼬리가 하늘의 별 3분의 1을 끌어다가 땅에 던졌어요. 용은 아이를 낳으려는 여자 앞에 서서, 그 여자가 해산하면 그 아기를 삼키려고 하고 있었어요."},{"n":5,"t":"여자가 아들을 낳았어요. 이 아이는 앞으로 철장(쇠 막대기)으로 만국을 다스릴 남자예요. 그 아기는 하나님 앞과 그분의 보좌 앞으로 들어 올려졌어요."},{"n":6,"t":"그 여자는 광야로 도망쳤어요. 거기에는 그 여자를 1,260일 동안 양육하기 위해 하나님께서 예비해 놓으신 곳이 있었어요."},{"n":7,"t":"하늘에 전쟁이 있었어요. 미가엘과 그의 천사들이 용과 더불어 싸웠고, 용과 그의 천사들도 싸웠지만,"},{"n":8,"t":"이기지 못해서 더 이상 하늘에 그들이 있을 곳이 없었어요."},{"n":9,"t":"큰 용이 쫓겨났는데, 그는 옛 뱀, 곧 \\"마귀\\"라고도 하고 \\"사탄\\"이라고도 하는, 온 세상을 미혹하는 자예요. 그가 땅으로 쫓겨났고, 그의 천사들도 그와 함께 쫓겨났어요."},{"n":10,"t":"내가 또 들으니, 하늘에 큰 음성이 있어 외쳤어요. \\"이제 우리 하나님의 구원과 능력과 나라와 그분의 그리스도의 권세가 이루어졌다. 우리 형제들을 참소(고발)하던 자, 곧 우리 하나님 앞에서 밤낮으로 참소하던 자가 쫓겨났다."},{"n":11,"t":"또 우리 형제들은 어린 양의 피와 자기들이 증언한 말씀으로 그를 이겼다. 그들은 죽기까지 자기 생명을 아끼지 않았다."},{"n":12,"t":"그러므로 하늘과 그 안에 사는 자들이여, 즐거워하라. 그러나 땅과 바다에는 화가 있을 것이다. 마귀가 자기의 때가 얼마 남지 않은 줄을 알고 크게 분노하여 너희에게 내려갔기 때문이다.\\""},{"n":13,"t":"용은 자기가 땅으로 쫓겨난 것을 보자, 남자아이를 낳은 여자를 핍박했어요."},{"n":14,"t":"그 여자는 큰 독수리의 두 날개를 받아서 광야의 자기 처소로 날아갔어요. 거기서 그 뱀의 얼굴을 피해, \\"한 때와 두 때와 반 때\\"(약 3년 반) 동안 양육을 받았어요."},{"n":15,"t":"뱀은 여자의 뒤에서 자기 입으로 물을 강처럼 토해 내서, 그 여자를 물에 떠내려가게 하려고 했어요."},{"n":16,"t":"그러나 땅이 그 여자를 도와, 입을 벌려 용의 입에서 토한 강물을 삼켰어요."},{"n":17,"t":"용은 그 여자에게 분노해서, 그 여자의 남은 자손, 곧 하나님의 계명을 지키며 예수님에 대한 증언을 가진 사람들과 싸우려고 가서, 바닷가 모래 위에 섰어요."},{"n":18,"t":""}]}},{"chapter":13,"title":"두 짐승","verses":{"krv":[{"n":1,"t":"내가 보니 바다에서 한 짐승이 나오는데 뿔이 열이요 머리가 일곱이라 그 뿔에는 열 면류관이 있고 그 머리들에는 참람한 이름들이 있더라"},{"n":2,"t":"내가 본 짐승은 표범과 비슷하고 그 발은 곰의 발 같고 그 입은 사자의 입 같은데 용이 자기의 능력과 보좌와 큰 권세를 그에게 주었더라"},{"n":3,"t":"그의 머리 하나가 상하여 죽게된 것 같더니 그 죽게 되었던 상처가 나으매 온 땅이 이상히 여겨 짐승을 따르고"},{"n":4,"t":"용이 짐승에게 권세를 주므로 용에게 경배하며 짐승에게 경배하여 가로되 누가 이 짐승과 같으뇨 누가 능히 이로 더불어 싸우리요 하더라"},{"n":5,"t":"또 짐승이 큰 말과 참람된 말하는 입을 받고 또 마흔두 달 일할 권세를 받으니라"},{"n":6,"t":"짐승이 입을 벌려 하나님을 향하여 훼방하되 그의 이름과 그의 장막 곧 하늘에 거하는 자들을 훼방하더라"},{"n":7,"t":"또 권세를 받아 성도들과 싸워 이기게 되고 각 족속과 백성과 방언과 나라를 다스리는 권세를 받으니"},{"n":8,"t":"죽임을 당한 어린 양의 생명책에 창세 이후로 녹명되지 못하고 이 땅에 사는 자들은 다 짐승에게 경배하리라"},{"n":9,"t":"누구든지 귀가 있거든 들을지어다"},{"n":10,"t":"사로잡는 자는 사로잡힐 것이요 칼에 죽이는 자는 자기도 마땅히 칼에 죽으리니 성도들의 인내와 믿음이 여기 있느니라"},{"n":11,"t":"내가 보매 또 다른 짐승이 땅에서 올라오니 새끼 양 같이 두 뿔이 있고 용처럼 말하더라"},{"n":12,"t":"저가 먼저 나온 짐승의 모든 권세를 그 앞에서 행하고 땅과 땅에 거하는 자들로 처음 짐승에게 경배하게 하니 곧 죽게 되었던 상처가 나은 자니라"},{"n":13,"t":"큰 이적을 행하되 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려오게 하고"},{"n":14,"t":"짐승 앞에서 받은 바 이적을 행함으로 땅에 거하는 자들을 미혹하며 땅에 거하는 자들에게 이르기를 칼에 상하였다가 살아난 짐승을 위하여 우상을 만들라 하더라"},{"n":15,"t":"저가 권세를 받아 그 짐승의 우상에게 생기를 주어 그 짐승의 우상으로 말하게 하고 또 짐승의 우상에게 경배하지 아니하는 자는 몇이든지 다 죽이게 하더라"},{"n":16,"t":"저가 모든 자 곧 작은 자나 큰 자나 부자나 빈궁한 자나 자유한 자나 종들로 그 오른손에나 이마에 표를 받게 하고"},{"n":17,"t":"누구든지 이 표를 가진 자 외에는 매매를 못하게 하니 이 표는 곧 짐승의 이름이나 그 이름의 수라"},{"n":18,"t":"지혜가 여기 있으니 총명 있는 자는 그 짐승의 수를 세어 보라 그 수는 사람의 수니 육백육십육이니라"}],"kids":[{"n":1,"t":"내가 보니, 바다에서 한 짐승이 올라오는데, 뿔이 열이고 머리가 일곱이었어요. 그 뿔들에는 열 개의 면류관이 있고, 그 머리들에는 (하나님을) 모독하는 이름들이 있었어요."},{"n":2,"t":"내가 본 그 짐승은 표범과 비슷했고, 발은 곰의 발 같고, 입은 사자의 입 같았어요. 용이 자기의 능력과 보좌와 큰 권세를 그 짐승에게 주었어요."},{"n":3,"t":"그 짐승의 머리 하나가 상해서 죽을 것 같아 보였는데, 그 죽을 뻔했던 상처가 나았어요. 그러자 온 땅이 놀라워하면서 그 짐승을 따랐어요."},{"n":4,"t":"용이 짐승에게 권세를 주었기 때문에 사람들이 용에게 경배했고, 또 짐승에게도 경배하면서 외쳤어요. \\"누가 이 짐승과 같은가? 누가 능히 이 짐승과 싸울 수 있겠는가?\\""},{"n":5,"t":"또 짐승은 큰 말과 (하나님을) 모독하는 말을 하는 입을 받았고, 마흔두 달 동안 활동할 권세를 받았어요."},{"n":6,"t":"짐승이 그 입을 벌려 하나님을 향해 모독하는 말을 했어요. 그분의 이름과 그분의 장막, 곧 하늘에 거하는 자들을 모독했어요."},{"n":7,"t":"또 권세를 받아 성도들과 싸워 이기게 되었고, 모든 족속과 백성과 언어와 나라를 다스리는 권세를 받았어요."},{"n":8,"t":"죽임을 당하신 어린 양의 생명책에, 세상이 창조되기 전부터 그 이름이 기록되지 않은 사람들, 곧 이 땅에 사는 사람들은 모두 그 짐승에게 경배할 거예요."},{"n":9,"t":"누구든지 귀가 있는 사람은 들으세요."},{"n":10,"t":"누가 사로잡혀야 할 사람이라면 사로잡힐 것이고, 칼로 죽여야 할 사람이라면 자기도 마땅히 칼로 죽임을 당할 거예요. 성도들의 인내와 믿음이 여기에 있어요."},{"n":11,"t":"내가 또 보니, 다른 짐승이 땅에서 올라오는데, 어린 양처럼 두 뿔이 있고, 용처럼 말했어요."},{"n":12,"t":"그 짐승은 먼저 나온 짐승의 모든 권세를 그 앞에서 행하고, 땅과 땅에 거하는 사람들로 하여금 처음 짐승, 곧 죽을 뻔한 상처가 나은 그 짐승에게 경배하게 했어요."},{"n":13,"t":"또 큰 표적들을 행해서, 심지어 사람들 앞에서 불이 하늘로부터 땅에 내려오게도 했어요."},{"n":14,"t":"또 그 짐승 앞에서 행하도록 받은 표적들을 행해서, 땅에 거하는 사람들을 미혹하고, 땅에 거하는 사람들에게 \\"칼에 상했다가 살아난 그 짐승을 위해 우상을 만들라\\"고 말했어요."},{"n":15,"t":"또 그것이 권세를 받아서, 그 짐승의 우상에게 생명의 기운을 주어 그 짐승의 우상이 말하게 했고, 또 그 짐승의 우상에게 경배하지 않는 사람은 누구든지 다 죽이게 했어요."},{"n":16,"t":"또 그것이 모든 사람, 곧 작은 자나 큰 자나, 부자나 가난한 자나, 자유로운 자나 종이나 모두에게, 그들의 오른손이나 이마에 표를 받게 했고,"},{"n":17,"t":"누구든지 이 표를 가진 사람이 아니면 사고팔지도 못하게 했어요. 이 표는 곧 그 짐승의 이름이거나 그 이름의 수예요."},{"n":18,"t":"여기에 지혜가 있어요. 총명 있는 사람은 그 짐승의 수를 세어 보세요. 그 수는 사람의 수인데, 666이에요."}]}},{"chapter":14,"title":"어린양과 144,000","verses":{"krv":[{"n":1,"t":"또 내가 보니 어린 양이 시온 산에 섰고 그와 함께 십사만 사천이 섰는데 그 이마에 어린 양의 이름과 그 아버지의 이름을 쓴 것이 있도다"},{"n":2,"t":"내가 하늘에서 나는 소리를 들으니 많은 물소리도 같고 큰 뇌성도 같은데 내게 들리는 소리는 거문고 타는 자들의 그 거문고 타는 것 같더라"},{"n":3,"t":"저희가 보좌와 네 생물과 장로들 앞에서 새 노래를 부르니 땅에서 구속함을 얻은 십사만 사천 인 밖에는 능히 이 노래를 배울 자가 없더라"},{"n":4,"t":"이 사람들은 여자로 더불어 더럽히지 아니하고 정절이 있는 자라 어린 양이 어디로 인도하든지 따라가는 자며 사람 가운데서 구속을 받아 처음 익은 열매로 하나님과 어린 양에게 속한 자들이니"},{"n":5,"t":"그 입에 거짓말이 없고 흠이 없는 자들이더라"},{"n":6,"t":"또 보니 다른 천사가 공중에 날아가는데 땅에 거하는 자들 곧 여러 나라와 족속과 방언과 백성에게 전할 영원한 복음을 가졌더라"},{"n":7,"t":"그가 큰 음성으로 가로되 하나님을 두려워하며 그에게 영광을 돌리라 이는 그의 심판하실 시간이 이르렀음이니 하늘과 땅과 바다와 물들의 근원을 만드신 이를 경배하라 하더라"},{"n":8,"t":"또 다른 천사 곧 둘째가 그 뒤를 따라 말하되 무너졌도다 무너졌도다 큰 성 바벨론이여 모든 나라를 그 음행으로 인하여 진노의 포도주로 먹이던 자로다 하더라"},{"n":9,"t":"또 다른 천사 곧 셋째가 그 뒤를 따라 큰 음성으로 가로되 만일 누구든지 짐승과 그의 우상에게 경배하고 이마에나 손에 표를 받으면"},{"n":10,"t":"그도 하나님의 진노의 포도주를 마시리니 그 진노의 잔에 섞인 것이 없이 부은 포도주라 거룩한 천사들 앞과 어린 양 앞에서 불과 유황으로 고난을 받으리니"},{"n":11,"t":"그 고난의 연기가 세세토록 올라가리로다 짐승과 그의 우상에게 경배하고 그 이름의 표를 받는 자는 누구든지 밤낮 쉼을 얻지 못하리라 하더라"},{"n":12,"t":"성도들의 인내가 여기 있나니 저희는 하나님의 계명과 예수 믿음을 지키는 자니라"},{"n":13,"t":"또 내가 들으니 하늘에서 음성이 나서 가로되 기록하라 자금 이후로 주 안에서 죽는 자들은 복이 있도다 하시매 성령이 가라사대 그러하다 저희 수고를 그치고 쉬리니 이는 저희의 행한 일이 따름이라 하시더라"},{"n":14,"t":"또 내가 보니 흰 구름이 있고 구름 위에 사람의 아들과 같은 이가 앉았는데 그 머리에는 금 면류관이 있고 그 손에는 이한 낫을 가졌더라"},{"n":15,"t":"또 다른 천사가 성전으로부터 나와 구름 위에 앉은 이를 향하여 큰 음성으로 외쳐 가로되 네 낫을 휘둘러 거두라 거둘 때가 이르러 땅에 곡식이 다 익었음이로다 하니"},{"n":16,"t":"구름 위에 앉으신 이가 낫을 땅에 휘두르매 곡식이 거두어지니라"},{"n":17,"t":"또 다른 천사가 하늘에 있는 성전에서 나오는데 또한 이한 낫을 가졌더라"},{"n":18,"t":"또 불을 다스리는 다른 천사가 제단으로부터 나와 이한 낫 가진 자를 향하여 큰 음성으로 불러 가로되 네 이한 낫을 휘둘러 땅의 포도송이를 거두라 그 포도가 익었느니라 하더라"},{"n":19,"t":"천사가 낫을 땅에 휘둘러 땅의 포도를 거두어 하나님의 진노의 큰 포도주 틀에 던지매"},{"n":20,"t":"성 밖에서 그 틀이 밟히니 틀에서 피가 나서 말굴레까지 닿았고 일천육백 스다디온에 퍼졌더라"}],"kids":[{"n":1,"t":"또 내가 보니, 어린 양이 시온 산에 서 계시고, 그분과 함께 14만 4천 명이 서 있었어요. 그들의 이마에는 어린 양의 이름과 그분의 아버지의 이름이 기록되어 있었어요."},{"n":2,"t":"내가 하늘에서 나는 소리를 들으니, 많은 물이 흐르는 소리 같기도 하고 큰 천둥소리 같기도 한데, 내게 들리는 그 소리는 거문고 타는 사람들이 거문고를 타는 소리 같았어요."},{"n":3,"t":"그들은 보좌와 네 생물과 장로들 앞에서 새 노래를 불렀어요. 땅에서 구원함을 받은(값 주고 사신 바 된) 그 14만 4천 명 외에는 아무도 그 노래를 배울 수 있는 사람이 없었어요."},{"n":4,"t":"이 사람들은 여자들과 함께 자기를 더럽히지 않은 사람들, 곧 순결한 사람들이에요. 그들은 어린 양이 어디로 인도하시든지 따라가는 사람들이고, 사람들 가운데서 구원함을 받아(값 주고 사신 바 되어), 처음 익은 열매로 하나님과 어린 양께 속한 사람들이에요."},{"n":5,"t":"그들의 입에는 거짓말이 없었고, 흠이 없는 사람들이었어요."},{"n":6,"t":"또 보니, 다른 천사가 공중에 날아가는데, 땅에 거하는 자들, 곧 모든 나라와 족속과 언어와 백성에게 전할 영원한 복음을 가지고 있었어요."},{"n":7,"t":"그가 큰 음성으로 외쳤어요. \\"하나님을 두려워하고 그분께 영광을 돌려라. 그분이 심판하실 시간이 이르렀다. 하늘과 땅과 바다와 물의 근원을 만드신 분을 경배하라.\\""},{"n":8,"t":"또 다른 천사, 곧 둘째 천사가 그 뒤를 따라가며 말했어요. \\"무너졌다, 무너졌다, 큰 성 바벨론이여! 모든 나라를 그 음행으로 인해 진노의 포도주를 마시게 하던 자다.\\""},{"n":9,"t":"또 다른 천사, 곧 셋째 천사가 그 뒤를 따라가며 큰 음성으로 외쳤어요. \\"누구든지 짐승과 그의 우상에게 경배하고, 이마에나 손에 그 표를 받는다면,"},{"n":10,"t":"그 사람도 하나님의 진노의 포도주를 마시게 될 것이다. 그것은 진노의 잔에 (희석되지 않고) 섞인 것 없이 부어진 포도주다. 그 사람은 거룩한 천사들 앞과 어린 양 앞에서, 불과 유황으로 고통을 받게 될 것이다."},{"n":11,"t":"그 고통의 연기가 영원무궁히 올라갈 것이다. 짐승과 그의 우상에게 경배하고 그 이름의 표를 받는 사람은 누구든지, 밤낮 쉼을 얻지 못할 것이다.\\""},{"n":12,"t":"성도들의 인내가 여기에 있어요. 그들은 하나님의 계명과 예수님께 대한 믿음을 지키는 사람들이에요."},{"n":13,"t":"또 내가 들으니, 하늘에서 음성이 났어요. \\"기록하라. 지금 이후로 주님 안에서 죽는 사람들은 복이 있다.\\" 성령께서 말씀하셨어요. \\"그렇다. 그들은 자기들의 수고를 그치고 쉴 것이다. 그들의 행한 일이 그들과 함께 따라가기 때문이다.\\""},{"n":14,"t":"또 내가 보니, 흰 구름이 있고, 그 구름 위에 \\"사람의 아들\\" 같은 분이 앉아 계셨어요. 그분의 머리에는 금 면류관이 있고, 그분의 손에는 날카로운 낫이 있었어요."},{"n":15,"t":"또 다른 천사가 성전에서 나와서, 구름 위에 앉으신 분을 향해 큰 음성으로 외쳤어요. \\"낫을 휘둘러 거두소서. 거둘 때가 왔습니다. 땅의 곡식이 다 익었습니다.\\""},{"n":16,"t":"구름 위에 앉으신 분이 낫을 땅에 휘두르시니, 곡식이 거두어졌어요."},{"n":17,"t":"또 다른 천사가 하늘에 있는 성전에서 나왔는데, 그도 날카로운 낫을 가지고 있었어요."},{"n":18,"t":"또 불을 다스리는 다른 천사가 제단에서 나와서, 날카로운 낫을 가진 그 천사를 향해 큰 음성으로 외쳤어요. \\"네 날카로운 낫을 휘둘러 땅의 포도송이를 거두어라. 그 포도가 익었다.\\""},{"n":19,"t":"그 천사가 낫을 땅에 휘둘러 땅의 포도를 거두어, 하나님의 진노의 큰 포도주 틀에 던졌어요."},{"n":20,"t":"성 밖에서 그 틀이 밟혔는데, 틀에서 피가 흘러나와 말의 굴레까지 닿았고, 1,600스타디온(약 300km)이나 퍼졌어요."}]}},{"chapter":15,"title":"마지막 일곱 재앙의 준비","verses":{"krv":[{"n":1,"t":"또 하늘에 크고 이상한 다른 이적을 보매 일곱 천사가 일곱 재앙을 가졌으니 곧 마지막 재앙이라 하나님의 진노가 이것으로 마치리로다"},{"n":2,"t":"또 내가 보니 불이 섞인 유리 바다 같은 것이 있고 짐승과 그의 우상과 그의 이름의 수를 이기고 벗어난 자들이 유리 바닷가에 서서 하나님의 거문고를 가지고"},{"n":3,"t":"하나님의 종 모세의 노래, 어린 양의 노래를 불러 가로되 주 하나님 곧 전능하신 이시여 하시는 일이 크고 기이하시도다 만국의 왕이시여 주의 길이 의롭고 참되시도다"},{"n":4,"t":"주여 누가 주의 이름을 두려워하지 아니하며 영화롭게 하지 아니하오리이까 오직 주만 거룩하시니이다 주의 의로우신 일이 나타났으매 만국이 와서 주께 경배하리이다 하더라"},{"n":5,"t":"또 이 일 후에 내가 보니 하늘에 증거 장막의 성전이 열리며"},{"n":6,"t":"일곱 재앙을 가진 일곱 천사가 성전으로부터 나와 맑고 빛난 세마포 옷을 입고 가슴에 금띠를 띠고"},{"n":7,"t":"네 생물 중에 하나가 세세에 계신 하나님의 진노를 가득히 담은 금 대접 일곱을 그 일곱 천사에게 주니"},{"n":8,"t":"하나님의 영광과 능력을 인하여 성전에 연기가 차게 되매 일곱 천사의 일곱 재앙이 마치기까지는 성전에 능히 들어갈 자가 없더라"}],"kids":[{"n":1,"t":"또 내가 하늘에서 크고 놀라운 다른 표징을 보았어요. 일곱 천사가 일곱 가지 재앙을 가지고 있었는데, 이것이 마지막 재앙이에요. 하나님의 진노가 이것으로 끝나게 돼요."},{"n":2,"t":"또 내가 보니, 불이 섞인 유리 바다 같은 것이 있고, 그 짐승과 그의 우상과 그의 이름의 수를 이기고 벗어난 사람들이 그 유리 바닷가에 서서, 하나님의 거문고를 들고서"},{"n":3,"t":"하나님의 종 모세의 노래와 어린 양의 노래를 부르고 있었어요. \\"주 하나님, 곧 전능하신 분이시여! 주님이 하시는 일은 크고 놀랍습니다. 만국의 왕이시여! 주님의 길은 의롭고 참되십니다."},{"n":4,"t":"주님이시여, 누가 주님의 이름을 두려워하지 않고, 영광스럽게 하지 않겠습니까? 오직 주님만이 거룩하십니다. 주님의 의로운 일들이 나타났으므로, 만국이 와서 주님께 경배할 것입니다.\\""},{"n":5,"t":"또 이 일 후에 내가 보니, 하늘에 증거의 장막인 성전이 열렸어요."},{"n":6,"t":"일곱 재앙을 가진 일곱 천사가 그 성전에서 나왔는데, 맑고 빛나는 세마포(고운 베) 옷을 입고, 가슴에 금띠를 띠고 있었어요."},{"n":7,"t":"네 생물 중 하나가 영원무궁히 살아 계신 하나님의 진노를 가득 담은 일곱 개의 금 대접을 그 일곱 천사에게 주었어요."},{"n":8,"t":"하나님의 영광과 능력으로 인해 성전에 연기가 가득 찼고, 그 일곱 천사의 일곱 재앙이 끝날 때까지 성전 안으로 들어갈 수 있는 사람이 아무도 없었어요."}]}},{"chapter":16,"title":"일곱 대접의 진노","verses":{"krv":[{"n":1,"t":"또 내가 들으니 성전에서 큰 음성이 나서 일곱 천사에게 말하되 너희는 가서 하나님의 진노의 일곱 대접을 땅에 쏟으라 하더라"},{"n":2,"t":"첫째가 가서 그 대접을 땅에 쏟으며 악하고 독한 헌데가 짐승의 표를 받은 사람들과 그 우상에게 경배하는 자들에게 나더라"},{"n":3,"t":"둘째가 그 대접을 바다에 쏟으매 바다가 곧 죽은 자의 피 같이 되니 바다 가운데 모든 생물이 죽더라"},{"n":4,"t":"셋째가 그 대접을 강과 물 근원에 쏟으매 피가 되더라"},{"n":5,"t":"내가 들으니 물을 차지한 천사가 가로되 전에도 계셨고 시방도 계신 거룩하신 이여 이렇게 심판하시니 의로우시도다"},{"n":6,"t":"저희가 성도들과 선지자들의 피를 흘렸으므로 저희로 피를 마시게 하신 것이 합당하니이다 하더라"},{"n":7,"t":"또 내가 들으니 제단이 말하기를 그러하다 주 하나님 곧 전능하신 이시여 심판하시는 것이 참되시고 의로우시도다 하더라"},{"n":8,"t":"넷째가 그 대접을 해에 쏟으매 해가 권세를 받아 불로 사람들을 태우니"},{"n":9,"t":"사람들이 크게 태움에 태워진지라 이 재앙들을 행하는 권세를 가지신 하나님의 이름을 훼방하며 또 회개하여 영광을 주께 돌리지 아니하더라"},{"n":10,"t":"또 다섯째가 그 대접을 짐승의 보좌에 쏟으니 그 나라가 곧 어두워지며 사람들이 아파서 자기 혀를 깨물고"},{"n":11,"t":"아픈 것과 종기로 인하여 하늘의 하나님을 훼방하고 저희 행위를 회개치 아니하더라"},{"n":12,"t":"또 여섯째가 그 대접을 큰 강 유브라데에 쏟으매 강물이 말라서 동방에서 오는 왕들의 길이 예비되더라"},{"n":13,"t":"또 내가 보매 개구리 같은 세 더러운 영이 용의 입과 짐승의 입과 거짓 선지자의 입에서 나오니"},{"n":14,"t":"저희는 귀신의 영이라 이적을 행하여 온 천하 임금들에게 가서 하나님 곧 전능하신 이의 큰 날에 전쟁을 위하여 그들을 모으더라"},{"n":15,"t":"보라 내가 도적 같이 오리니 누구든지 깨어 자기 옷을 지켜 벌거벗고 다니지 아니하며 자기의 부끄러움을 보이지 아니하는 자가 복이 있도다"},{"n":16,"t":"세 영이 히브리 음으로 아마겟돈이라 하는 곳으로 왕들을 모으더라"},{"n":17,"t":"일곱째가 그 대접을 공기 가운데 쏟으매 큰 음성이 성전에서 보좌로부터 나서 가로되 되었다 하니"},{"n":18,"t":"번개와 음성들과 뇌성이 있고 또 지진이 있어 어찌 큰지 사람이 땅에 있어 옴으로 이같이 큰 지진이 없었더라"},{"n":19,"t":"큰 성이 세 갈래로 갈라지고 만국의 성들도 무너지니 큰 성 바벨론이 하나님 앞에 기억하신 바 되어 그의 맹렬한 진노의 포도주 잔을 받으매"},{"n":20,"t":"각 섬도 없어지고 산악도 간 데 없더라"},{"n":21,"t":"또 중수가 한 달란트나 되는 큰 우박이 하늘로부터 사람들에게 내리매 사람들이 그 박재로 인하여 하나님을 훼방하니 그 재앙이 심히 큼이러라"}],"kids":[{"n":1,"t":"또 내가 들으니, 성전에서 큰 음성이 나서 일곱 천사에게 말씀하셨어요. \\"너희는 가서, 하나님의 진노의 일곱 대접을 땅에 쏟아라.\\""},{"n":2,"t":"첫째 천사가 가서 그 대접을 땅에 쏟았어요. 그러자 악하고 독한 종기가 짐승의 표를 받은 사람들과 그 우상에게 경배하는 사람들에게 생겨났어요."},{"n":3,"t":"둘째 천사가 그 대접을 바다에 쏟으니, 바다가 곧 죽은 사람의 피같이 되었고, 바다 안의 모든 생물이 죽었어요."},{"n":4,"t":"셋째 천사가 그 대접을 강들과 물의 근원에 쏟으니, 그것이 피가 되었어요."},{"n":5,"t":"내가 들으니, 물을 다스리는 천사가 말했어요. \\"전에도 계셨고 지금도 계신 거룩하신 분이시여, 이렇게 심판하시니 의로우십니다."},{"n":6,"t":"그들이 성도들과 예언자들의 피를 흘렸기 때문에, 주님께서 그들에게 피를 마시게 하신 것이 합당합니다.\\""},{"n":7,"t":"또 내가 들으니, 제단이 외쳤어요. \\"그렇습니다. 주 하나님, 곧 전능하신 분이시여! 주님이 심판하시는 것이 참되고 의로우십니다.\\""},{"n":8,"t":"넷째 천사가 그 대접을 해에 쏟으니, 해가 권세를 받아 불로 사람들을 태웠어요."},{"n":9,"t":"사람들이 큰 더위에 태워졌어요. 그러나 그들은 이 재앙들을 행하시는 권세를 가지신 하나님의 이름을 모독했고, 회개하여 그분께 영광을 돌리지 않았어요."},{"n":10,"t":"또 다섯째 천사가 그 대접을 짐승의 보좌에 쏟으니, 그의 나라가 곧 어두워졌고, 사람들이 아파서 자기 혀를 깨물었어요."},{"n":11,"t":"또 그 아픔과 종기 때문에 하늘의 하나님을 모독했고, 자기들의 행위를 회개하지 않았어요."},{"n":12,"t":"또 여섯째 천사가 그 대접을 큰 강 유브라데에 쏟으니, 강물이 말라서 동방에서 오는 왕들의 길이 예비되었어요."},{"n":13,"t":"또 내가 보니, 개구리 같은 세 더러운 영이 용의 입과 짐승의 입과 거짓 예언자의 입에서 나왔어요."},{"n":14,"t":"이들은 귀신의 영들이에요. 그것들이 표적을 행하면서 온 천하의 왕들에게 가서, 하나님, 곧 전능하신 분의 큰 날에 일어날 전쟁을 위해 그들을 모았어요."},{"n":15,"t":"\\"보아라, 내가 도둑처럼 올 것이다. 깨어서 자기 옷을 지켜 벌거벗고 다니지 않고, 자기의 부끄러움을 드러내지 않는 사람은 복이 있다.\\""},{"n":16,"t":"세 영이 왕들을, 히브리어로 \\"아마겟돈\\"이라고 하는 곳에 모았어요."},{"n":17,"t":"일곱째 천사가 그 대접을 공중에 쏟으니, 큰 음성이 성전에서, 보좌로부터 나서 외쳤어요. \\"다 이루어졌다!\\""},{"n":18,"t":"그러자 번개와 음성들과 천둥이 있었고, 또 큰 지진이 있었는데, 사람이 땅 위에 있은 이래로 이렇게 큰 지진은 없었어요."},{"n":19,"t":"그 큰 성이 세 갈래로 갈라졌고, 만국의 성들도 무너졌어요. 큰 성 바벨론이 하나님 앞에 기억되어, 그분의 맹렬한 진노의 포도주 잔을 받게 되었어요."},{"n":20,"t":"모든 섬이 사라졌고, 산들도 자취가 없어졌어요."},{"n":21,"t":"또 무게가 한 달란트(약 30~40kg)나 되는 큰 우박이 하늘에서 사람들 위에 내리니, 사람들이 그 우박의 재앙 때문에 하나님을 모독했어요. 그 재앙이 너무도 컸기 때문이에요."}]}},{"chapter":17,"title":"큰 음녀 바벨론","verses":{"krv":[{"n":1,"t":"또 일곱 대접을 가진 일곱 천사 중 하나가 와서 내게 말하여 가로되 이리 오라 많은 물 위에 앉은 큰 음녀의 받을 심판을 네게 보이리라"},{"n":2,"t":"땅의 임금들도 그로 더불어 음행하였고 땅에 거하는 자들도 그 음행의 포도주에 취하였다 하고"},{"n":3,"t":"곧 성령으로 나를 데리고 광야로 가니라 내가 보니 여자가 붉은 빛 짐승을 탔는데 그 짐승의 몸에 참람된 이름들이 가득하고 일곱 머리와 열 뿔이 있으며"},{"n":4,"t":"그 여자는 자주빛과 붉은빛 옷을 입고 금과 보석과 진주로 꾸미고 손에 금잔을 가졌는데 가증한 물건과 그의 음행의 더러운 것들이 가득하더라"},{"n":5,"t":"그 이마에 이름이 기록되었으니 비밀이라, 큰 바벨론이라, 땅의 음녀들과 가증한 것들의 어미라 하였더라"},{"n":6,"t":"또 내가 보매 이 여자가 성도들의 피와 예수의 증인들의 피에 취한지라 내가 그 여자를 보고 기이히 여기고 크게 기이히 여기니"},{"n":7,"t":"천사가 가로되 왜 기이히 여기느냐 내가 여자와 그의 탄 바 일곱 머리와 열 뿔 가진 짐승의 비밀을 네게 이르리라"},{"n":8,"t":"네가 본 짐승은 전에 있었다가 시방 없으나 장차 무저갱으로부터 올라와 멸망으로 들어갈 자니 땅에 거하는 자들로서 창세 이후로 생명책에 녹명되지 못한 자들이 이전에 있었다가 시방 없으나 장차 나올 짐승을 보고 기이히 여기리라"},{"n":9,"t":"지혜 있는 뜻이 여기 있으니 그 일곱 머리는 여자가 앉은 일곱 산이요"},{"n":10,"t":"또 일곱 왕이라 다섯은 망하였고 하나는 있고 다른 이는 아직 이르지 아니하였으나 이르면 반드시 잠간 동안 계속하리라"},{"n":11,"t":"전에 있었다가 시방 없어진 짐승은 여덟째 왕이니 일곱 중에 속한 자라 저가 멸망으로 들어가리라"},{"n":12,"t":"네가 보던 열 뿔은 열 왕이니 아직 나라를 얻지 못하였으나 다만 짐승으로 더불어 임금처럼 권세를 일시 동안 받으리라"},{"n":13,"t":"저희가 한 뜻을 가지고 자기의 능력과 권세를 짐승에게 주더라"},{"n":14,"t":"저희가 어린 양으로 더불어 싸우려니와 어린 양은 만주의 주시요 만왕의 왕이시므로 저희를 이기실 터이요 또 그와 함께 있는 자들 곧 부르심을 입고 빼내심을 얻고 진실한 자들은 이기리로다"},{"n":15,"t":"또 천사가 내게 말하되 네가 본 바 음녀의 앉은 물은 백성과 무리와 열국과 방언들이니라"},{"n":16,"t":"네가 본 바 이 열 뿔과 짐승이 음녀를 미워하여 망하게 하고 벌거벗게 하고 그 살을 먹고 불로 아주 사르리라"},{"n":17,"t":"하나님이 자기 뜻대로 할 마음을 저희에게 주사 한 뜻을 이루게 하시고 저희 나라를 그 짐승에게 주게 하시되 하나님 말씀이 응하기까지 하심이니라"},{"n":18,"t":"또 내가 본 바 여자는 땅의 임금들을 다스리는 큰 성이라 하더라"}],"kids":[{"n":1,"t":"또 일곱 대접을 가진 일곱 천사 중 하나가 와서 내게 말했어요. \\"이리 오라. 많은 물 위에 앉은 큰 음녀가 받을 심판을 네게 보여 주겠다."},{"n":2,"t":"땅의 왕들도 그 여자와 음행을 하였고, 땅에 거하는 사람들도 그 여자의 음행의 포도주에 취해 있었다.\\""},{"n":3,"t":"그 천사가 곧 성령으로 나를 데리고 광야로 갔어요. 내가 보니, 한 여자가 붉은빛 짐승을 타고 있는데, 그 짐승의 몸에는 (하나님을) 모독하는 이름들이 가득했고, 머리가 일곱이고 뿔이 열이었어요."},{"n":4,"t":"그 여자는 자주빛과 붉은빛 옷을 입고, 금과 보석과 진주로 꾸미고, 손에 금잔을 들고 있었는데, 그 잔에는 가증한 물건과 그 여자의 음행의 더러운 것들이 가득했어요."},{"n":5,"t":"그 여자의 이마에 이름이 기록되어 있었어요. \\"비밀, 큰 바벨론, 땅의 음녀들과 가증한 것들의 어미.\\""},{"n":6,"t":"또 내가 보니, 이 여자가 성도들의 피와 예수님의 증인들의 피에 취해 있었어요. 내가 그 여자를 보고 매우 놀랐어요."},{"n":7,"t":"천사가 내게 말했어요. \\"왜 놀라느냐? 그 여자와 그 여자가 탄, 일곱 머리와 열 뿔을 가진 짐승의 비밀을 내가 네게 말해 주겠다."},{"n":8,"t":"네가 본 그 짐승은 전에는 있었다가 지금은 없지만, 앞으로 무저갱(끝없이 깊은 구덩이)에서 올라와 멸망으로 들어갈 자다. 땅에 거하는 사람들 가운데서, 세상 창조 이후로 생명책에 그 이름이 기록되지 않은 사람들은, 전에 있다가 지금은 없지만 앞으로 나타날 그 짐승을 보고 놀랄 것이다."},{"n":9,"t":"여기에 지혜가 있는 뜻이 있다. 그 일곱 머리는 그 여자가 앉아 있는 일곱 산이다."},{"n":10,"t":"또 일곱 왕이기도 한데, 다섯은 망했고, 하나는 (현재) 있고, 다른 하나는 아직 오지 않았지만, 오게 되면 반드시 잠시 동안 머무를 것이다."},{"n":11,"t":"전에 있었다가 지금은 없는 그 짐승은 여덟째 왕인데, 일곱 중 하나에 속한 자다. 그 자도 멸망으로 들어갈 것이다."},{"n":12,"t":"네가 본 열 뿔은 열 왕인데, 그들은 아직 나라를 얻지 못했지만, 짐승과 함께 잠시 동안 왕으로서 권세를 받을 것이다."},{"n":13,"t":"그들은 한 뜻을 가지고서, 자기들의 능력과 권세를 그 짐승에게 줄 것이다."},{"n":14,"t":"그들이 어린 양과 싸울 것이지만, 어린 양은 만주의 주이시고 만왕의 왕이시므로 그들을 이기실 것이다. 또 그분과 함께 있는 사람들, 곧 부르심을 받고 택하심을 받고 신실한 사람들도 그분과 함께 이길 것이다.\\""},{"n":15,"t":"또 천사가 내게 말했어요. \\"네가 본, 음녀가 앉아 있는 물은 백성과 무리와 나라들과 언어들이다."},{"n":16,"t":"네가 본 그 열 뿔과 짐승은 음녀를 미워해서, 그 여자를 망하게 하고, 벌거벗게 하고, 그 살을 먹고, 불로 완전히 태워 버릴 것이다."},{"n":17,"t":"이는 하나님께서 자기 뜻을 이루실 마음을 그들에게 주셔서, 한 뜻으로 자기들의 나라를 그 짐승에게 주게 하신 것이고, 하나님의 말씀이 다 이루어질 때까지 그렇게 하시는 것이다."},{"n":18,"t":"또 네가 본 그 여자는 땅의 왕들을 다스리는 큰 성이다.\\""}]}},{"chapter":18,"title":"바벨론의 멸망","verses":{"krv":[{"n":1,"t":"이 일 후에 다른 천사가 하늘에서 내려오는 것을 보니 큰 권세를 가졌는데 그의 영광으로 땅이 환하여지더라"},{"n":2,"t":"힘센 음성으로 외쳐 가로되 무너졌도자 무너졌도다 큰 성 바벨론이여 귀신의 처소와 각종 더러운 영의 모이는 곳과 각종 더럽고 가증한 새의 모이는 곳이 되었도다"},{"n":3,"t":"그 음행의 진노의 포도주를 인하여 만국이 무너졌으며 또 땅의 왕들이 그로 더불어 음행하였으며 땅의 상고들도 그 사치의 세력을 인하여 치부하였도다 하더라"},{"n":4,"t":"또 내가 들으니 하늘로서 다른 음성이 나서 가로되 내 백성아, 거기서 나와 그의 죄에 참예하지 말고 그의 받을 재앙들을 받지 말라"},{"n":5,"t":"그 죄는 하늘에 사무쳤으며 하나님은 그의 불의한 일을 기억하신지라"},{"n":6,"t":"그가 준 그대로 그에게 주고 그의 행위대로 갑절을 갚아주고 그의 섞은 잔에도 갑절이나 섞어 그에게 주라"},{"n":7,"t":"그가 어떻게 자기를 영화롭게 하였으며 사치하였든지 그만큼 고난과 애통으로 갚아 주라 그가 마음에 말하기를 나는 여황으로 앉은 자요 과부가 아니라 결단코 애통을 당하지 아니하리라 하니"},{"n":8,"t":"그러므로 하루 동안에 그 재앙들이 이르리니 곧 사망과 애통과 흉년이라 그가 또한 불에 살라지리니 그를 심판하신 주 하나님은 강하신 자이심이니라"},{"n":9,"t":"그와 함께 음행하고 사치하던 땅의 왕들이 그 불붙는 연기를 보고 위하여 울고 가슴을 치며"},{"n":10,"t":"그 고난을 무서워하여 멀리 서서 가로되 화 있도다 화 있도다 큰 성, 견고한 성 바벨론이여 일시간에 네 심판이 이르렀다 하리로다"},{"n":11,"t":"땅의 상고들이 그를 위하여 울고 애통하는 것은 다시 그 상품을 사는 자가 없음이라"},{"n":12,"t":"그 상품은 금과 은과 보석과 진주와 세마포와 자주 옷감과 비단과 붉은 옷감이요 각종 향목과 각종 상아 기명이요 값진 나무와 진유와 철과 옥석으로 만든 각종 기명이요"},{"n":13,"t":"계피와 향료와 향과 향유와 유향과 포도주와 감람유와 고운 밀가루와 밀과 소와 양과 말과 수레와 종들과 사람의 영혼들이라"},{"n":14,"t":"바벨론아 네 영혼의 탐하던 과실이 네게서 떠났으며 맛있는 것들과 빛난 것들이 다 없어졌으니 사람들이 결코 이것들을 다시 보지 못하리로다"},{"n":15,"t":"바벨론을 인하여 치부한 이 상품의 상고들이 그 고난을 무서워하여 멀리 서서 울고 애통하여"},{"n":16,"t":"가로되 화 있도다 화 있도다 큰 성이여 세마포와 자주와 붉은 옷을 입고 금과 보석과 진주로 꾸민 것인데"},{"n":17,"t":"그러한 부가 일시간에 망하였도다 각 선장과 각처를 다니는 선객들과 선인들과 바다에서 일하는 자들이 멀리 서서"},{"n":18,"t":"그 불붙는 연기를 보고 외쳐 가로되 이 큰 성과 같은 성이 어디 있느뇨 하며"},{"n":19,"t":"티끌을 자기 머리에 뿌리고 울고 애통하여 외쳐 가로되 화 있도다 화 있도다 이 큰 성이여 바다에서 배 부리는 모든 자들이 너의 보배로운 상품을 인하여 치부하였더니 일시간에 망하였도다"},{"n":20,"t":"하늘과 성도들과 사도들과 선지자들아 그를 인하여 즐거워하라 하나님이 너희를 신원하시는 심판을 그에게 하셨음이라 하더라"},{"n":21,"t":"이에 한 힘센 천사가 큰 맷돌 같은 돌을 들어 바다에 던져 가로되 큰 성 바벨론이 이같이 몹시 떨어져 결코 다시 보이지 아니하리로다"},{"n":22,"t":"또 거문고 타는 자와 풍류하는 자와 퉁소 부는 자와 나팔 부는 자들의 소리가 결코 다시 네 가운데서 들리지 아니하고 물론 어떠한 세공업자든지 결코 다시 네 가운데서 보이지 아니하고 또 맷돌 소리가 다시 네 가운데서 들리지 아니하고"},{"n":23,"t":"등불 빛이 결코 다시 네 가운데서 비취지 아니하고 신랑과 신부의 음성이 결코 다시 네 가운데서 들리지 아니하리로다 너의 상고들은 땅의 왕족들이라 네 복술을 인하여 만국이 미혹되었도다"},{"n":24,"t":"선지자들과 성도들과 및 땅 위에서 죽임을 당한 모든 자의 피가 이 성중에서 보였느니라 하더라"}],"kids":[{"n":1,"t":"이 일 후에 내가 보니, 다른 천사 하나가 큰 권세를 가지고 하늘에서 내려왔는데, 그의 영광으로 땅이 환해졌어요."},{"n":2,"t":"그가 힘찬 음성으로 외쳤어요. \\"무너졌다, 무너졌다, 큰 성 바벨론이여! 귀신의 처소가 되었고, 각종 더러운 영이 모이는 곳, 각종 더럽고 가증한 새들이 모이는 곳이 되었다."},{"n":3,"t":"그 음행의 진노의 포도주 때문에 모든 나라가 무너졌고, 땅의 왕들도 그 여자와 음행을 했고, 땅의 상인들도 그 사치의 힘으로 부자가 되었다.\\""},{"n":4,"t":"또 내가 들으니, 하늘에서 다른 음성이 나서 외쳤어요. \\"내 백성아, 거기서 나오너라. 그 죄에 참여하지 말고, 그 받을 재앙들을 받지 말아라."},{"n":5,"t":"그 죄가 하늘에까지 사무쳤고, 하나님께서 그의 불의한 일들을 기억하셨다."},{"n":6,"t":"그가 준 그대로 그에게 갚아 주고, 그가 행한 대로 갑절로 갚아 주어라. 그가 (남에게) 섞어 준 잔에도 갑절로 섞어 그에게 주어라."},{"n":7,"t":"그가 자기를 얼마나 영화롭게 하고 사치했든지 그만큼 고난과 슬픔으로 갚아 주어라. 그가 마음에 \\"나는 여왕으로 앉아 있는 자다. 과부가 아니다. 결코 슬픔을 당하지 않을 것이다\\"라고 말하고 있다."},{"n":8,"t":"그러므로 하루 동안에 그 재앙들이 임할 것이다. 곧 사망과 슬픔과 흉년이다. 또 그는 불에 살라질 것이다. 그를 심판하시는 주 하나님은 강하신 분이시기 때문이다.\\""},{"n":9,"t":"그와 함께 음행하고 사치하던 땅의 왕들이, 그가 불에 타는 연기를 보고 그를 위해 울며 가슴을 칠 거예요."},{"n":10,"t":"그들은 그 고난을 두려워해서 멀리 서서 외칠 거예요. \\"화가 있다, 화가 있다, 큰 성, 견고한 성 바벨론이여! 한 시간 만에 네 심판이 임했다.\\""},{"n":11,"t":"땅의 상인들도 그를 위해 울고 슬퍼할 거예요. 더 이상 그들의 상품을 사 줄 사람이 없기 때문이에요."},{"n":12,"t":"그 상품은 금, 은, 보석, 진주, 고운 베, 자주색 옷감, 비단, 붉은 옷감, 모든 종류의 향나무, 모든 종류의 상아 그릇, 값진 나무, 청동, 철, 대리석으로 만든 모든 종류의 그릇,"},{"n":13,"t":"계피, 향료, 향, 향유, 유향, 포도주, 올리브 기름, 고운 밀가루, 밀, 소, 양, 말, 수레, 종들, 그리고 사람의 영혼이에요."},{"n":14,"t":"\\"바벨론아, 네 영혼이 탐내던 과일이 너에게서 떠났고, 맛있는 것들과 빛나는 것들이 다 없어졌고, 사람들이 결코 이것들을 다시 보지 못할 것이다.\\""},{"n":15,"t":"바벨론으로 인해 부자가 된 이 상품의 상인들이, 그 고난을 두려워해서 멀리 서서 울며 슬퍼하면서"},{"n":16,"t":"외칠 거예요. \\"화가 있다, 화가 있다, 큰 성이여! 고운 베와 자주와 붉은 옷을 입고, 금과 보석과 진주로 꾸민 곳이"},{"n":17,"t":"한 시간 만에 그 부가 망해 버렸다!\\" 모든 선장과 곳곳을 다니는 선객들과 선원들과, 바다에서 일하는 모든 사람이 멀리 서서,"},{"n":18,"t":"그가 불에 타는 연기를 보고 외칠 거예요. \\"이 큰 성과 같은 성이 어디 있는가?\\""},{"n":19,"t":"그들은 자기 머리에 티끌을 뿌리며 울고 슬퍼하면서 외칠 거예요. \\"화가 있다, 화가 있다, 이 큰 성이여! 바다에서 배를 부리는 모든 사람이 너의 보배로운 상품 때문에 부자가 되었는데, 한 시간 만에 망해 버렸다!\\""},{"n":20,"t":"\\"하늘과 성도들과 사도들과 예언자들이여, 그를 인해 즐거워하라. 하나님께서 너희에게 (행한) 일을 그에게 갚아 주는 심판을 하셨다!\\""},{"n":21,"t":"그러자 한 힘센 천사가 큰 맷돌 같은 돌을 들어서 바다에 던지면서 외쳤어요. \\"큰 성 바벨론이 이렇게 무섭게 던져져, 결코 다시 보이지 않을 것이다."},{"n":22,"t":"또 거문고 타는 사람과 음악을 연주하는 사람과 피리 부는 사람과 나팔 부는 사람들의 소리가 결코 다시 네 가운데서 들리지 않을 것이고, 어떤 종류의 세공업자도 결코 다시 네 가운데서 보이지 않을 것이고, 또 맷돌 소리가 다시 네 가운데서 들리지 않을 것이고,"},{"n":23,"t":"등불 빛이 결코 다시 네 가운데서 비치지 않을 것이고, 신랑과 신부의 음성이 결코 다시 네 가운데서 들리지 않을 것이다. 너의 상인들은 땅의 큰 사람들이었고, 너의 마술로 만국이 미혹되었기 때문이다."},{"n":24,"t":"또 예언자들과 성도들과, 땅 위에서 죽임을 당한 모든 사람의 피가 이 성에서 발견되었기 때문이다.\\""}]}},{"chapter":19,"title":"어린양의 혼인잔치와 백마 타신 자","verses":{"krv":[{"n":1,"t":"이 일 후에 내가 들으니 하늘에 허다한 무리의 큰 음성 같은 것이 있어 가로되 할렐루야 구원과 영광과 능력이 우리 하나님께 있도다"},{"n":2,"t":"그의 심판은 참되고 의로운지라 음행으로 땅을 더럽게 한 큰 음녀를 심판하사 자기 종들의 피를 그의 손에 갚으셨도다 하고"},{"n":3,"t":"두번째 가로되 할렐루야 하더니 그 연기가 세세토록 올라가더라"},{"n":4,"t":"또 이십사 장로와 네 생물이 엎드려 보좌에 앉으신 하나님께 경배하여 가로되 아멘 할렐루야 하니"},{"n":5,"t":"보좌에서 음성이 나서 가로되 하나님의 종들 곧 그를 경외하는 너희들아 무론대소하고 다 우리 하나님께 찬송하라"},{"n":6,"t":"또 내가 들으니 허다한 무리의 음성도 같고 많은 물소리도 같고 큰 뇌성도 같아서 가로되 할렐루야 주 우리 하나님 곧 전능하신 이가 통치하시도다"},{"n":7,"t":"우리가 즐거워하고 크게 기뻐하여 그에게 영광을 돌리세 어린 양의 혼인 기약이 이르렀고 그 아내가 예비하였으니"},{"n":8,"t":"그에게 허락하사 빛나고 깨끗한 세마포를 입게 하셨은즉 이 세마포는 성도들의 옳은 행실이로다 하더라"},{"n":9,"t":"천사가 내게 말하기를 기록하라 어린 양의 혼인 잔치에 청함을 입은 자들이 복이 있도다 하고 또 내게 말하되 이것은 하나님의 참되신 말씀이라 하기로"},{"n":10,"t":"내가 그 발 앞에 엎드려 경배하려 하니 그가 나더러 말하기를 나는 너와 및 예수의 증거를 받은 네 형제들과 같이 된 종이니 삼가 그리하지 말고 오직 하나님께 경배하라 예수의 증거는 대언의 영이라 하더라"},{"n":11,"t":"또 내가 하늘이 열린 것을 보니 보라 백마와 탄 자가 있으니 그 이름은 충신과 진실이라 그가 공의로 심판하며 싸우더라"},{"n":12,"t":"그 눈이 불꽃 같고 그 머리에 많은 면류관이 있고 또 이름 쓴 것이 하나가 있으니 자기 밖에 아는 자가 없고"},{"n":13,"t":"또 그가 피 뿌린 옷을 입었는데 그 이름은 하나님의 말씀이라 칭하더라"},{"n":14,"t":"하늘에 있는 군대들이 희고 깨끗한 세마포를 입고 백마를 타고 그를 따르더라"},{"n":15,"t":"그의 입에서 이한 검이 나오니 그것으로 만국을 치겠고 친히 저희를 철장으로 다스리며 또 친히 하나님 곧 전능하신 이의 맹렬한 진노의 포도주 틀을 밟겠고"},{"n":16,"t":"그 옷과 그 다리에 이름 쓴 것이 있으니 만왕의 왕이요 만주의 주라 하였더라"},{"n":17,"t":"또 내가 보니 한 천사가 해에 서서 공중에 나는 모든 새를 향하여 큰 음성으로 외쳐 가로되 와서 하나님의 큰 잔치에 모여"},{"n":18,"t":"왕들의 고기와 장군들의 고기와 장사들의 고기와 말들과 그 탄 자들의 고기와 자유한 자들이나 종들이나 무론대소하고 모든 자의 고기를 먹으라 하더라"},{"n":19,"t":"또 내가 보매 그 짐승과 땅의 임금들과 그 군대들이 모여 그 말 탄 자와 그의 군대로 더불어 전쟁을 일으키다가"},{"n":20,"t":"짐승이 잡히고 그 앞에서 이적을 행하던 거짓 선지자도 함께 잡혔으니 이는 짐승의 표를 받고 그의 우상에게 경배하던 자들을 이적으로 미혹하던 자라 이 둘이 산 채로 유황불 붙는 못에 던지우고"},{"n":21,"t":"그 나머지는 말 탄 자의 입으로 나오는 검에 죽으매 모든 새가 그 고기로 배불리우더라"}],"kids":[]}},{"chapter":20,"title":"천 년 왕국과 마지막 심판","verses":{"krv":[{"n":1,"t":"또 내가 보매 천사가 무저갱 열쇠와 큰 쇠사슬을 그 손에 가지고 하늘로서 내려와서"},{"n":2,"t":"용을 잡으니 곧 옛 뱀이요 마귀요 사단이라 잡아 일천 년 동안 결박하여"},{"n":3,"t":"무저갱에 던져 잠그고 그 위에 인봉하여 천 년이 차도록 다시는 만국을 미혹하지 못하게 하였다가 그 후에는 반드시 잠간 놓이리라"},{"n":4,"t":"또 내가 보좌들을 보니 거기 앉은 자들이 있어 심판하는 권세를 받았더라 또 내가 보니 예수의 증거와 하나님의 말씀을 인하여 목 베임을 받은 자의 영혼들과 또 짐승과 그의 우상에게 경배하지도 아니하고 이마와 손에 그의 표를 받지도 아니한 자들이 살아서 그리스도로 더불어 천 년 동안 왕 노릇 하니"},{"n":5,"t":"(그 나머지 죽은 자들은 그 천 년이 차기까지 살지 못하더라) 이는 첫째 부활이라"},{"n":6,"t":"이 첫째 부활에 참예하는 자들은 복이 있고 거룩하도다 둘째 사망이 그들을 다스리는 권세가 없고 도리어 그들이 하나님과 그리스도의 제사장이 되어 천 년 동안 그리스도로 더불어 왕 노릇 하리라"},{"n":7,"t":"천 년이 차매 사단이 그 옥에서 놓여"},{"n":8,"t":"나와서 땅의 사방 백성 곧 곡과 마곡을 미혹하고 모아 싸움을 붙이리니 그 수가 바다 모래 같으리라"},{"n":9,"t":"저희가 지면에 널리 퍼져 성도들의 진과 사랑하시는 성을 두르매 하늘에서 불이 내려와 저희를 소멸하고"},{"n":10,"t":"또 저희를 미혹하는 마귀가 불과 유황 못에 던지우니 거기는 그 짐승과 거짓 선지자들도 있어 세세토록 밤낮 괴로움을 받으리라"},{"n":11,"t":"또 내가 크고 흰 보좌와 그 위에 앉으신 자를 보니 땅과 하늘이 그 앞에서 피하여 간 데 없더라"},{"n":12,"t":"또 내가 보니 죽은 자들이 무론대소하고 그 보좌 앞에 섰는데 책들이 펴 있고 또 다른 책이 펴졌으니 곧 생명책이라 죽은 자들이 자기 행위를 따라 책들에 기록된 대로 심판을 받으니"},{"n":13,"t":"바다가 그 가운데서 죽은 자들을 내어주고 또 사망과 음부도 그 가운데서 죽은 자들을 내어주매 각 사람이 자기의 행위대로 심판을 받고"},{"n":14,"t":"사망과 음부도 불못에 던지우니 이것은 둘째 사망 곧 불못이라"},{"n":15,"t":"누구든지 생명책에 기록되지 못한 자는 불못에 던지우더라"}],"kids":[]}},{"chapter":21,"title":"새 하늘과 새 땅","verses":{"krv":[{"n":1,"t":"또 내가 새 하늘과 새 땅을 보니 처음 하늘과 처음 땅이 없어졌고 바다도 다시 있지 않더라"},{"n":2,"t":"또 내가 보매 거룩한 성 새 예루살렘이 하나님께로부터 하늘에서 내려오니 그 예비한 것이 신부가 남편을 위하여 단장한 것 같더라"},{"n":3,"t":"내가 들으니 보좌에서 큰 음성이 나서 가로되 보라 하나님의 장막이 사람들과 함께 있으매 하나님이 저희와 함께 거하시리니 저희는 하나님의 백성이 되고 하나님은 친히 저희와 함께 계셔서"},{"n":4,"t":"모든 눈물을 그 눈에서 씻기시매 다시 사망이 없고 애통하는 것이나 곡하는 것이나 아픈 것이 다시 있지 아니하리니 처음 것들이 다 지나갔음이러라"},{"n":5,"t":"보좌에 앉으신 이가 가라사대 보라 내가 만물을 새롭게 하노라 하시고 또 가라사대 이 말은 신실하고 참되니 기록하라 하시고"},{"n":6,"t":"또 내게 말씀하시되 이루었도다 나는 알파와 오메가요 처음과 나중이라 내가 생명수 샘물로 목마른 자에게 값없이 주리니"},{"n":7,"t":"이기는 자는 이것들을 유업으로 얻으리라 나는 저의 하나님이 되고 그는 내 아들이 되리라"},{"n":8,"t":"그러나 두려워하는 자들과 믿지 아니하는 자들과 흉악한 자들과 살인자들과 행음자들과 술객들과 우상 숭배자들과 모든 거짓말하는 자들은 불과 유황으로 타는 못에 참예하리니 이것이 둘째 사망이라"},{"n":9,"t":"일곱 대접을 가지고 마지막 일곱 재앙을 담은 일곱 천사 중 하나가 나아와서 내게 말하여 가로되 이리 오라 내가 신부 곧 어린 양의 아내를 네게 보이리라 하고"},{"n":10,"t":"성령으로 나를 데리고 크고 높은 산으로 올라가 하나님께로부터 하늘에서 내려오는 거룩한 성 예루살렘을 보이니"},{"n":11,"t":"하나님의 영광이 있으매 그 성의 빛이 지극히 귀한 보석 같고 벽옥과 수정 같이 맑더라"},{"n":12,"t":"크고 높은 성곽이 있고 열두 문이 있는데 문에 열두 천사가 있고 그 문들 위에 이름을 썼으니 이스라엘 자손 열두 지파의 이름들이라"},{"n":13,"t":"동편에 세 문, 북편에 세 문, 남편에 세 문, 서편에 세 문이니"},{"n":14,"t":"그 성에 성곽은 열두 기초석이 있고 그 위에 어린 양의 십이 사도의 열두 이름이 있더라"},{"n":15,"t":"내게 말하는 자가 그 성과 그 문들과 성곽을 척량하려고 금 갈대를 가졌더라"},{"n":16,"t":"그 성은 네모가 반듯하여 장광이 같은지라 그 갈대로 그 성을 척량하니 일만 이천 스다디온이요 장과 광과 고가 같더라"},{"n":17,"t":"그 성곽을 척량하매 일백사십사 규빗이니 사람의 척량 곧 천사의 척량이라"},{"n":18,"t":"그 성곽은 벽옥으로 쌓였고 그 성은 정금인데 맑은 유리 같더라"},{"n":19,"t":"그 성의 성곽의 기초석은 각색 보석으로 꾸몄는데 첫째 기초석은 벽옥이요 둘째는 남보석이요 셋째는 옥수요 넷째는 녹보석이요"},{"n":20,"t":"다섯째는 홍마노요 여섯째는 홍보석이요 일곱째는 황옥이요 여덟째는 녹옥이요 아홉째는 담황옥이요 열째는 비취옥이요 열한째는 청옥이요 열두째는 자정이라"},{"n":21,"t":"그 열두 문은 열두 진주니 문마다 한 진주요 성의 길은 맑은 유리 같은 정금이더라"},{"n":22,"t":"성 안에 성전을 내가 보지 못하였으니 이는 주 하나님 곧 전능하신 이와 및 어린 양이 그 성전이심이라"},{"n":23,"t":"그 성은 해나 달의 비췸이 쓸 데 없으니 이는 하나님의 영광이 비취고 어린 양이 그 등이 되심이라"},{"n":24,"t":"만국이 그 빛 가운데로 다니고 땅의 왕들이 자기 영광을 가지고 그리로 들어오리라"},{"n":25,"t":"성문들을 낮에 도무지 닫지 아니하리니 거기는 밤이 없음이라"},{"n":26,"t":"사람들이 만국의 영광과 존귀를 가지고 그리로 들어오겠고"},{"n":27,"t":"무엇이든지 속된 것이나 가증한 일 또는 거짓말하는 자는 결코 그리로 들어오지 못하되 오직 어린 양의 생명책에 기록된 자들뿐이라"}],"kids":[]}},{"chapter":22,"title":"생명수의 강과 주의 재림 약속","verses":{"krv":[{"n":1,"t":"또 저가 수정 같이 맑은 생명수의 강을 내게 보이니 하나님과 및 어린 양의 보좌로부터 나서"},{"n":2,"t":"길 가운데로 흐르더라 강 좌우에 생명나무가 있어 열두 가지 실과를 맺히되 달마다 그 실과를 맺히고 그 나무 잎사귀들은 만국을 소성하기 위하여 있더라"},{"n":3,"t":"다시 저주가 없으며 하나님과 그 어린 양의 보좌가 그 가운데 있으리니 그의 종들이 그를 섬기며"},{"n":4,"t":"그의 얼굴을 볼 터이요 그의 이름도 저희 이마에 있으리라"},{"n":5,"t":"다시 밤이 없겠고 등불과 햇빛이 쓸 데 없으니 이는 주 하나님이 저희에게 비취심이라 저희가 세세토록 왕 노릇 하리로다"},{"n":6,"t":"또 그가 내게 말하기를 이 말은 신실하고 참된지라 주 곧 선지자들의 영의 하나님이 그의 종들에게 결코 속히 될 일을 보이시려고 그의 천사를 보내셨도다"},{"n":7,"t":"보라 내가 속히 오리니 이 책의 예언의 말씀을 지키는 자가 복이 있으리라 하더라"},{"n":8,"t":"이것들을 보고 들은 자는 나 요한이니 내가 듣고 볼 때에 이 일을 내게 보이던 천사의 발 앞에 경배하려고 엎드렸더니"},{"n":9,"t":"저가 내게 말하기를 나는 너와 네 형제 선지자들과 또 이 책의 말을 지키는 자들과 함께 된 종이니 그리하지 말고 오직 하나님께 경배하라 하더라"},{"n":10,"t":"또 내게 말하되 이 책의 예언의 말씀을 인봉하지 말라 때가 가까우니라"},{"n":11,"t":"불의를 하는 자는 그대로 불의를 하고 더러운 자는 그대로 더럽고 의로운 자는 그대로 의를 행하고 거룩한 자는 그대로 거룩되게 하라"},{"n":12,"t":"보라 내가 속히 오리니 내가 줄 상이 내게 있어 각 사람에게 그의 일한 대로 갚아 주리라"},{"n":13,"t":"나는 알파와 오메가요 처음과 나중이요 시작과 끝이라"},{"n":14,"t":"그 두루마기를 빠는 자들은 복이 있으니 이는 저희가 생명나무에 나아가며 문들을 통하여 성에 들어갈 권세를 얻으려 함이로다"},{"n":15,"t":"개들과 술객들과 행음자들과 살인자들과 우상 숭배자들과 및 거짓말을 좋아하며 지어내는 자마다 성 밖에 있으리라"},{"n":16,"t":"나 예수는 교회들을 위하여 내 사자를 보내어 이것들을 너희에게 증거하게 하였노라 나는 다윗의 뿌리요 자손이니 곧 광명한 새벽별이라 하시더라"},{"n":17,"t":"성령과 신부가 말씀하시기를 오라 하시는도다 듣는 자도 오라 할 것이요 목마른 자도 올 것이요 또 원하는 자는 값없이 생명수를 받으라 하시더라"},{"n":18,"t":"내가 이 책의 예언의 말씀을 듣는 각인에게 증거하노니 만일 누구든지 이것들 외에 더하면 하나님이 이 책에 기록된 재앙들을 그에게 더하실 터이요"},{"n":19,"t":"만일 누구든지 이 책의 예언의 말씀에서 제하여 버리면 하나님이 이 책에 기록된 생명나무와 및 거룩한 성에 참예함을 제하여 버리시리라"},{"n":20,"t":"이것들을 증거하신 이가 가라사대 내가 진실로 속히 오리라 하시거늘 아멘 주 예수여 오시옵소서"},{"n":21,"t":"주 예수의 은혜가 모든 자들에게 있을지어다 아멘"}],"kids":[]}}]}');

